// System imports related to reading in package.json file
import fs = require('fs');
import path = require('path');

// SDK imports
import {GoalSet} from '../goal/GoalSet';
import {Goal} from '../goal/Goal';
import {GoalProvider} from '../goal/GoalProvider';
import {Memory} from './Memory';
import {MotivationSystem} from '../motivation';
import {ActionSystem} from '../action/ActionSystem';
import {GoalDrivenAction} from '../action/GoalDrivenAction';
import {
    ActionResult, SkillSwitchHandler, InitOptions, GoalFinishedStatus, GoalProgressStatus,
    ListenState
} from '../common/Types';
import {State, ActionEvents, Updater} from '.';
import {
    HJGoalProvider,
    HJNoMatchGoalProvider,
    HJOnlyGoalProvider,
    ProactiveGreetingGoalProvider,
    SnuggleGoalProvider} from '../goal/goalproviders';
import {DateProvider, DefaultDateProvider} from "./DateProvider";
import {OpportunityDetector} from "../proactive/OpportunityDetector";
import {ActionSystemConfiguration} from './Types';
import {TimeUtils} from 'jibo-cai-utils';
import {CircadianState} from 'jibo-common-types';

// Only importing type definition
import JiboImport = require('../../../jibo'); // NOTE: only for type declaration, not runtime dependency

// Debug interface
import {TunableDebug} from './TunableDebug';
import {HeadTouchGoalProvider} from "../goal/goalproviders/HeadTouchGoalProvider";
import {log} from './log';
import {Handler} from "jibo-typed-events/dts/Event";

// Read package.json file and grab proactive trigger options
const findRoot = require('find-root');
const ROOT_PATH = findRoot(__dirname);
let pegasusProactiveTrigger = false;
let disableProactiveTrigger = false;
try {
    const packageFile = fs.readFileSync(path.join(ROOT_PATH, 'package.json'), 'utf8');
    const packageJson = JSON.parse(packageFile);
    if (packageJson.options) {
        pegasusProactiveTrigger = packageJson.options.pegasusProactiveTrigger;
        disableProactiveTrigger = packageJson.options.disableProactiveTrigger;
    }
} catch (error) {
    throw new Error(`Error loading package.json in jibo-action-system for options: ${error.message}`);
}


export {}; // For type definition purposes

/**
 * @class ActionRuntime
 * @memberof jibo.action.common
 * @private
 */
export class ActionRuntime {

    /*
     * Systems
     */
    public goals = new GoalSet(this);
    public actions = new ActionSystem(this);
    public motivations = new MotivationSystem(this);
    public proactive: OpportunityDetector = null;
    public events = new ActionEvents();

    /**
     * This should not be a part of the external API
     * @private
     */
    jibo: typeof JiboImport;

    skillSwitcher: SkillSwitchHandler;

    activeGoals: GoalDrivenAction[] = [];

    /**
     * The dateProvider insulates us from the weirdness of the system being stuck in UTC.
     * @type {any}
     */
    dateProvider: DateProvider = new DefaultDateProvider();

    memory = new Memory(this);

    /*
     * Goal providers
     */
    goalProviders: GoalProvider[] = []; // Order constraint: has to happen before creating any providers
    hjGoalProvider: HJGoalProvider;
    proactiveGreetingGoalProvider: ProactiveGreetingGoalProvider;

    private _currentSkillName: string;
    private _skillStartTime = this.dateProvider.getDate();
    private _currentListenState: ListenState;
    private _currentCircadianState: CircadianState;

    private _updater = new Updater();

    private _options: InitOptions;

    private setListenTrigger: Handler<any>;
    private setListenOff: Handler<any>;

    /**
     * Adds a goal provider to this action runtime instance
     * @param goalProvider
     */
    addGoalProvider(goalProvider: GoalProvider) {
        this.goalProviders.push(goalProvider);
    }

    /**
     * Initializes and creates the polling loop
     */
    async init(options: InitOptions): Promise<any> {
        this._options = options;
        if (options.autoUpdate === undefined) {
            options.autoUpdate = true;
        }
        this.jibo = options.jibo;

        // Install goal providers
        this.hjGoalProvider = new HJGoalProvider(this);
        this.addGoalProvider(this.hjGoalProvider);
        // Here we add the goal providers that we don't need explicit pointers to
        this.addGoalProvider(new HJNoMatchGoalProvider(this));
        this.addGoalProvider(new HJOnlyGoalProvider(this));
        this.addGoalProvider(new SnuggleGoalProvider(this));
        this.addGoalProvider(new HeadTouchGoalProvider(this));

        // Initialize the proactive trigger either as
        // A) original proactive goal provider
        // B) proactive opportunity detector
        if (pegasusProactiveTrigger) {
            log.info('Creating opportunity detector to provide proactive triggers');
            this.proactive = new OpportunityDetector(this);
            this.proactive.setDisableProactiveTrigger(disableProactiveTrigger);
            this.proactive.init();
        } else {
            log.info('Creating goal provider to provide proactive greeting triggers');
            this.proactiveGreetingGoalProvider = new ProactiveGreetingGoalProvider(this);
            this.proactiveGreetingGoalProvider.setDisableProactiveTrigger(disableProactiveTrigger);
            this.addGoalProvider(this.proactiveGreetingGoalProvider);
        }

        // Initialize goal providers
        this.goalProviders.forEach(gp => gp.init());

        // We register all updateables
        this._updater.addUpdateable(() => this.motivations.update(), 1000);
        this._updater.addUpdateable(() => this.update(), 1000);
        // Update pegasus proactive
        if (pegasusProactiveTrigger) {
            this._updater.addUpdateable(() => this.proactive.update(), 100);
        }

        // On every new goal event
        this.events.goalAdded.on((goal: Goal) => {
            this.handleIncomingGoal(goal);
        });

        // Subscribe to Jibo's update timer
        if (this._options.autoUpdate) {
            (<any>this.updateAll).isGlobalTimer = true; // Tells Be's Timerspy that we are allowed to persist across skill boundaries
            this.jibo.timer.on('update', this.updateAll);
        }

        this.setListenTrigger = () => {
            this.setListenState(ListenState.HJ_TRIGGERED_LISTEN);
        };
        this.setListenOff = () => {
            this.setListenState(ListenState.NOT_LISTENING);
        };

        this.jibo.jetstream.events.globalTurnStarted.on(this.setListenTrigger);
        this.jibo.jetstream.events.globalTurnResult.on(this.setListenOff);

        // Setup Tunable debug interface if `jibo-tunable` is present
        TunableDebug.setup(this);
    }

    dispose() {
        // Unsubscribe from Jibo's update timer
        if (this._options && this._options.autoUpdate) {
            this.jibo.timer.off('update', this.updateAll);
        }

        // Dispose goal providers
        this.goalProviders.forEach(gp => gp.dispose());
        this.goalProviders = [];

        this.jibo.jetstream.events.globalTurnStarted.removeListener(this.setListenTrigger);
        this.jibo.jetstream.events.globalTurnResult.removeListener(this.setListenOff);

        // Dispose proactive if exists
        if (this.proactive) {
            this.proactive.dispose();
        }

        this._updater.clear();
    }

    /**
     * Configure the action system.
     * @param {ActionSystemConfiguration} configOptions
     * @memberOf ActionRuntime
     */
    configure(configOptions: ActionSystemConfiguration): void {
        if (configOptions.hasOwnProperty('orientToHJ')) {
            this.hjGoalProvider.setListening(configOptions.orientToHJ);
        }
    }

    /**
     * Set the current skill name
     * @param {string} name
     */
    set currentSkillName(name: string) {
        const oldSkillName = this._currentSkillName;
        this._currentSkillName = name;
        if (oldSkillName !== name) {
            this._skillStartTime = this.dateProvider.getDate();
            this.events.skillChange.emit([oldSkillName, this._currentSkillName]);
        }
    }

    /**
     * Set the current circadian state
     * @param {CircadianState} state
     */
    set currentCircadianState(state: CircadianState) {
        this._currentCircadianState = state;
        log.debug(`Action system circadian state set to ${state}.`);
    }

    get currentSkillName(): string {
        return this._currentSkillName;
    }

    /**
     * Creates a state representation
     * @return {State}
     */
    public createState(): State {
        const now = this.dateProvider.getDate();
        // TODO this needs to be tested
        return {
            time: now,
            users: this.jibo.lps.identity.getPresentPersons(),
            skillName: this.currentSkillName,
            skillStartTime: this._skillStartTime,
            partOfDay: TimeUtils.getPartOfDay(now),
            circadian: this._currentCircadianState,
            listenState: this._currentListenState
        };
    }

    /**
     * Updates the whole behavior system
     */
    update() {
        // If we don't have a current goal, we attempt to pick another one
        if (!this.activeGoals.length) {
            this.pursueNextGoal();
        }
    }

    private async handleIncomingGoal(goal: Goal): Promise<void> {
        log.info(`Incoming new goal '${goal.name}'`);
        const state = this.createState();
        if (!goal.isEligible(state)) {
            log.info(`not currently eligible, in queue`);
            return;
        }
        // If we have no active goal, simply pursue the next one
        if (!this.activeGoals.length) {
            // If we had no active goal, then we go ahead and pick a new one
            this.pursueNextGoal();
        } else {
            // Check to see if this goal can be achieved in parallel with all current goals of HIGHER or SAME priority
            for (let i = 0; i < this.activeGoals.length; i++) {
                const entry = this.activeGoals[i];
                if ((entry.goal.options.priority >= goal.options.priority) &&
                    !this.goals.goalParallelism.canBeAchievedInParallel(goal, entry.goal)) {
                    log.info(`incoming goal is of lower priority and can not be performed in parallel with existing goal: '${entry.goal.name}', is queued`);
                    return;
                }
            }

            // Now we iterate through all active goals of LOWER priority and see which ones can be canceled in order to enable this one
            let shouldBeCanceled = this.activeGoals.filter(entry => {
                return ((entry.goal.options.priority < goal.options.priority) &&
                    !this.goals.goalParallelism.canBeAchievedInParallel(goal, entry.goal));
            });

            if (shouldBeCanceled.length) {
                const goalNames = shouldBeCanceled.map(e => e.goal.name).join(', ');
                log.info(`Canceling following lower priority goals in favor of incoming one: '${goalNames}'`);
                await Promise.all(shouldBeCanceled.map(e => this.cancelGoalDrivenAction(e)));
            }

            await this.achieveGoal(state, goal);
        }
    }

    /**
     * An update function pointer used to update our internal updater
     */
    private updateAll = () => this._updater.update();

    /**
     * Pick a new goal and pursue it
     * @return {Promise}
     */
    private async pursueNextGoal(): Promise<ActionResult|void> {
        // Choose the next goal
        const state = this.createState();
        const goal: Goal = this.goals.chooseGoal(state);
        if (goal) {
            log.debug(`Selected goal to pursue '${goal.name}'`); // debug level because this method gets called in a loop
            return this.achieveGoal(state, goal);
        }
    }

    private async cancelGoalDrivenAction(current: GoalDrivenAction): Promise<void> {
        current.goal.setFinishedStatus(GoalFinishedStatus.CANCELED);
        // We tell the previous action to stop and wait for it to finish
        // TODO add timeout logic
        await current.action.cancel();
        if (current.currentRunPromise) {
            await current.currentRunPromise;
        }
    }

    /**
     * Attempts to find an action to achieve a current goal. Will cancel
     * existing goal if one is currently being pursued.
     * @param {State} state
     * @param {Goal} newGoal
     * @return {Promise<ActionResult>}
     */
    private async achieveGoal(state: State, newGoal: Goal): Promise<ActionResult> {
        // Choose the best action
        const action = this.actions.chooseAction(state, newGoal);
        if (action) {
            log.debug(`attempting to achieve goal`, newGoal.name, `with action`, action.name);
            newGoal.setProgressStatus(GoalProgressStatus.SELECTED);
            const goalDrivenAction = new GoalDrivenAction(newGoal, action, this);
            log.debug('created new goal driven action based on ', newGoal.name);
            this.activeGoals.push(goalDrivenAction);
            // Make sure the order is always ascending in priority
            this.activeGoals.sort((a, b) => a.goal.options.priority - b.goal.options.priority);

            // The cleanup that should happen both after success or failure of the action taken
            const postAction = () => {
                // Remove goal from current list of active goals
                const ind = this.activeGoals.indexOf(goalDrivenAction);
                if (ind >= 0) {
                    this.activeGoals.splice(ind, 1);
                }
                // Check for another goal on the next tick
                process.nextTick(() => {
                    this.pursueNextGoal();
                });
            };

            return goalDrivenAction.run()
                .then(result => {
                    postAction();
                    return result;
                }).catch((e) => {
                    postAction();
                    throw e;
                });
        }
        else {
            // Otherwise we simply set the status of the goal to INITIAL since it did not get selected
            newGoal.setProgressStatus(GoalProgressStatus.INITIAL);
            return null;
        }
    }

    /**
     * Set the current listen state
     * @param {ListenState} listenState
     */
    private setListenState(listenState: ListenState) {
        log.debug('Setting listen state to ', listenState);
        this._currentListenState = listenState;
    }
}
