/**
 * @namespace jibo.action.types
 * @intdocs
 */

import {Action} from '../action/Action';
import {Goal} from '../goal/Goal';

/**
 * Description of the part of day, consisting of a basic part of day (MORNING, AFTERNOON, EVENING, NIGHT)
 * and a detail (EARLY, MID, LATE).
 * @interface jibo.action.types#PartOfDay
 * @intdocs
 */
import {PartOfDay} from 'jibo-cai-utils';
export {
    PartOfDay
};

/**
 * Enum of the finished status of a goal
 * @typedef jibo.action.types#GoalFinishedStatus
 * @property {String} NOT_FINISHED
 * @property {String} SUCCEEDED
 * @property {String} FAILED
 * @property {String} CANCELED
 * @property {String} CULLED
 * @intdocs
 */
export enum GoalFinishedStatus {
    NOT_FINISHED = 'NOT_FINISHED',
    SUCCEEDED = 'SUCCEEDED',
    FAILED = 'FAILED',
    CANCELED = 'CANCELED',
    CULLED = 'CULLED',
}

/**
 * Enum of the listening states
 * @typedef jibo.action.types#ListenState
 * @property {String} HJ_TRIGGERED_LISTEN
 * @property {String} NOT_LISTENING
 * @intdocs
 */
export enum ListenState {
    HJ_TRIGGERED_LISTEN = 'HJ_TRIGGERED_LISTEN',
    NOT_LISTENING = 'NOT_LISTENING',
}

/**
 * Enum of the progress status of a goal
 * @typedef jibo.action.types#GoalProgressStatus
 * @property {String} INITIAL
 * @property {String} SELECTED
 * @property {String} CULLED
 * @property {String} ATTEMPTED
 * @property {String} FINISHED
 * @intdocs
 */
export enum GoalProgressStatus {
    INITIAL = 'INITIAL',
    SELECTED = 'SELECTED',
    FINISHED = 'FINISHED',
    ATTEMPTED = 'ATTEMPTED',
}

/**
 * Enum of the outcome of an action
 * @typedef jibo.action.types#ActionResult
 * @property {String} SUCCEEDED
 * @property {String} FAILED
 * @property {String} CANCELED
 * @property {String} TIMEOUT
 * @intdocs
 */
export enum ActionResult {
    SUCCEEDED = 'SUCCEEDED',
    FAILED = 'FAILED',
    CANCELED = 'CANCELED',
    TIMEOUT = 'TIMEOUT',
}

/**
 * Enum of current status of an action
 * @typedef jibo.action.types#ActionStatus
 * @property {String} RUNNING
 * @property {String} NOT_RUNNING
 * @intdocs
 */
export enum ActionStatus {
    RUNNING = 'RUNNING',
    NOT_RUNNING = 'NOT_RUNNING',
}

// * @memberof jibo.action.types

/**
 * Enum of skill switch outcomes
 * @typedef jibo.action.types#Status
 * @property {String} SUCCEEDED
 * @property {String} FAILED
 * @intdocs
 */
export enum Status {
    SUCCEEDED = 'SUCCEEDED',
    FAILED = 'FAILED',
}


/**
 * @private
 */
export type Callback<T> = (err?: string|Error, data?: T) => void;

/**
 * This callback is displayed as part of the Requester class.
 * @memberof jibo.action.types
 * @callback SkillSwitchHandler
 * @param {String} skillName - Name of skill to switch to
 * @param {Object} skillData - Data to provide to launched skill
 * @return {Promise.<jibo.action.types#Status>}
 * @intdocs
 */
export type SkillSwitchHandler = (skillName: string, skillData: any) => Promise<Status>;


/**
 * Constructor options for the Jibo actions system
 * @memberof jibo.action.types
 * @interface InitOptions
 * @property {Jibo} jibo - The Jibo runtime
 * @property {boolean} [autoUpdate=true] - Whether action system should create its own update loop
 * @intdocs
 */
export interface InitOptions {
    jibo: any;
    autoUpdate?: any;
}

/**
 * Enum of the goal priority type
 * @typedef jibo.action.types#GoalPriorityType
 * @property {String} REGULAR
 * @property {String} SINGLETON_KEEP_FIRST
 * @property {String} SINGLETON_KEEP_LAST
 * @intdocs
 */
export enum GoalPriorityType {
    REGULAR = 'REGULAR',
    SINGLETON_KEEP_FIRST = 'SINGLETON_KEEP_FIRST',
    SINGLETON_KEEP_LAST = 'SINGLETON_KEEP_LAST',
}

/**
 * @private
 */
export interface GoalOptions {
    priority: number;
    priorityType?: GoalPriorityType;
    maxAttempts?: number;
    action?: ActionProvider;
    criteria?: Criteria;
}

/**
 * @private
 */
export interface HJData {
    primary: ConfidencePosition;
    alternate?: ConfidencePosition;
}

/**
 * @private
 */
export interface ConfidencePosition {
    position: Point3;
    confidence: number;
}

/**
 * @private
 */
export interface Point3 {
    x: number;
    y: number;
    z: number;
}

/**
 * Selection criteria for a goal. If a parameter in this interface is provided, then
 * the criteria defined by that parameter is enforced for a goal to be eligible
 * @interface jibo.action.types#Criteria
 * @property {Date} [startTime] - The earliest time a goal can be selected
 * @property {Date} [endTime] - The latest time a goal can be selected
 * @property {String} [personPresent] - The id of the person that needs to be present
 * @property {String} [currentSkill] - The name of the current skill that needs to be active
 * @intdocs
 */
export interface Criteria {
    startTime?: Date;
    endTime?: Date;
    personPresent?: string;
    currentSkill?: string;
}

/**
 * Specific preferences by a Be Skill with respect to what Action system should do when launching into it.
 * @interface jibo.action.types#BeSkillPreferences
 * @property {boolean} [cancelOrientOnStart=false] - Specifies whether this skill wants to stop any
 * ongoing orientation action that might be active when skill switch occurs
 * @intdocs
 */
export interface BeSkillPreferences {
    cancelOrientOnStart?: boolean;
}

/**
 * Skill switch goal data
 * @interface jibo.action.types#BeSSWGoalData
 * @property {String} skillName - Name of skill to switch into
 * @property {Object} skillOptions - Data to provide to launched skill
 * @property {number} beSkillPriority - Be skill priority
 * @property {jibo.action.types#BeSkillPreferences} beSkillPreferences - Action system specific preferences for this Be Skill
 * @property {jibo.action.types#Criteria} [criteria] - Selection criteria for goal
 * @intdocs
 */
export interface BeSSWGoalData {
    skillName: string;
    skillOptions: any;
    beSkillPriority: number;
    beSkillPreferences: BeSkillPreferences;
    criteria?: Criteria;
}

/**
 * Skill switch goal data
 * @interface jibo.action.types#SSWGoalData
 * @property {String} skillName - Name of skill to switch into
 * @property {Object} skillOptions - Data to provide to launched skill
 * @property {jibo.action.types#Criteria} [criteria] - Selection criteria for goal
 * @intdocs
 */
export interface SSWGoalData  {
    skillName: string;
    skillOptions: any;
    criteria?: Criteria;
}

/**
 * Animation goal data
 * @interface jibo.action.types#AnimationGoalData
 * @property {String} [category] - Name of the desired animation category
 * @property {string[]} [includeMeta] Array of meta include filters
 * @property {string[]} [includeSomeMeta] Array of meta includeSome filters
 * @property {string[]} [excludeMeta] Array of meta exclude filters
 * @property {boolean} [randomOrientation] Whether to randomize orientation
 * @property {String} [name] - Name of the desired animation
 * @property {jibo.action.types#Criteria} [criteria] - Selection criteria for goal
 * @property {boolean} [muteAudio] - Whether to mute the audio in the animation
 * @intdocs
 */
export interface AnimationGoalData {
    category?: string;
    includeMeta?: string[];
    includeSomeMeta?: string[];
    excludeMeta?: string[];
    randomOrientation?: boolean;
    name?: string;
    criteria?: Criteria;
    muteAudio?: boolean;
}

/**
 * @private
 */
export type ActionProvider = (goal?: Goal) => Action;


/**
 * Enumerated motivational Drive names
 * @typedef jibo.action.types#DriveName
 * @property {String} SOCIAL
 * @property {String} PLAYFUL
 * @property {String} HELPFUL
 * @intdocs
 */
export enum DriveName {
    SOCIAL = 'SOCIAL',
    PLAYFUL = 'PLAYFUL',
    HELPFUL = 'HELPFUL',
}

/**
 * Constructor options for the Jibo actions system
 * @memberof jibo.action.types
 * @interface ActionOptions
 * @property {Map<jibo.action.types#DriveName, number>} [driveEffects] - Describes to what extent this action satisfies each type of drive
 * @property {number} [timeoutMs] - Describes the timeout value of this action in milliseconds
 * @intdocs
 */
export interface ActionOptions {
    driveEffects?: Map<DriveName, number>;
    timeoutMs?: number;
}

/**
 * Configuration options for the jibo.action API.
 * @interface jibo.action.types#ActionSystemConfiguration
 * @export
 * @property {boolean} [orientToHJ] `true` to orient to a Hey Jibo.
 * @default true
 * @intdocs
 */
export interface ActionSystemConfiguration {
    orientToHJ?: boolean;
}

/**
 * Enumerated snuggle types
 * @typedef jibo.action.types#SnuggleType
 * @property {String} HATCH_OPEN
 * @property {String} HATCH_CLOSE
 * @property {String} PLUG
 * @property {String} UNPLUG
 * @intdocs
 */
export enum SnuggleType {
    HATCH_OPEN = 'HATCH_OPEN',
    HATCH_CLOSE = 'HATCH_CLOSE',
    PLUG = 'PLUG',
    UNPLUG = 'UNPLUG',
    AXIS_FAULT = 'AXIS_FAULT',
}
