// External
import { TimeUtils } from 'jibo-cai-utils';
// Internal
import { log as parentLog } from '../../log';
import { InhibitingSignal } from '../InhibitingSignal';

export {}; // For Type definition purposes

const log = parentLog.createChild('SignalNoMatchStatus'); 

/**
 * SignalNoMatchStatus
 * (Type): Inhibiting
 * (Pass Condition): When a GlobalNoMatch has NOT occured recently. 
 * (Description): Ensures that we avoid proactive behaviors when we recently "failed" an HJ interaction.  
 * Recency is set by NO_MATCH_EXPIRE_TIMEOUT.
 * @private
 */
export class SignalNoMatchStatus extends InhibitingSignal {

    public static RECENT_NO_MATCH_EXPIRY_MS = TimeUtils.minutesToMs(5);  //5 minutes

    // Timestamp of last no-match in milliseconds
    private lastNoMatchMs = -1;

    /** 
     * Init 
     */
    public init(): void { 
        this.parent.jibo.globalEvents.shared.noGlobalMatch.on(this.handleNoMatchBind);
     }

    /** 
     * Dispose 
     */
    public dispose(): void { 
        this.parent.jibo.globalEvents.shared.noGlobalMatch.removeListener(this.handleNoMatchBind);
     }

    /** 
     * Evaluates whether a minimum time of RECENT_NO_MATCH_EXPIRY_MS has passed since the last idle no-match 
     */
    public evaluate(): boolean {
        const sinceLastNoMatch = this.parent.dateProvider.getDate().getTime() - this.lastNoMatchMs;
        if (sinceLastNoMatch > SignalNoMatchStatus.RECENT_NO_MATCH_EXPIRY_MS) {
            log.debug(`Passed: Last no-match was not recent: ${sinceLastNoMatch}ms is greater than ${SignalNoMatchStatus.RECENT_NO_MATCH_EXPIRY_MS}ms`);
            return true;
        } else {
            log.info(`Failed: Last no-match was too recent: ${sinceLastNoMatch}ms is less than ${SignalNoMatchStatus.RECENT_NO_MATCH_EXPIRY_MS}ms`);
            return false;
        }
    }

    // Internal bind function
    private handleNoMatchBind = () => this.handleNoMatch(); 

    /**
     * Called whenever a global no-match event is emitted
     */
    private handleNoMatch(): void {
        this.lastNoMatchMs = this.parent.dateProvider.getDate().getTime();
        log.debug("Heard global no match");
    }

    /**
     * Configure the static parameters of this signal, should be done before instantiation
     * @param {any} configuration Configuration of signal 
     */
    public static Configure(configuration: any) {
        try {
            SignalNoMatchStatus.RECENT_NO_MATCH_EXPIRY_MS = TimeUtils.minutesToMs(configuration.RECENT_NO_MATCH_EXPIRY_MINS);
        } catch (e) {
            log.error("Could not configure static variables based on configuration file: ", e);
        }
    }
}