import {Goal} from '../Goal';
import {ActionRuntime} from '../../common/ActionRuntime';
import {SSWGoalData, GoalPriorityType} from '../../common/Types';
import {GoalPriority} from '../GoalPriority';


export {}; // For Type definition purposes

/**
 * @private
 */
export class SSWGoal extends Goal {

    constructor(parent: ActionRuntime, public data: SSWGoalData, name=`Skill Launch: '${data.skillName}'`) {
        super(parent, name, {
            priority: GoalPriority.SkillSwitch,
            criteria: data.criteria,
            priorityType: GoalPriorityType.SINGLETON_KEEP_LAST
        });
    }
}
