import { SkillNames } from '../../../common/Utils';
import { log as parentLog } from '../../log';
import { InhibitingSignal } from '../InhibitingSignal';


const log = parentLog.createChild('SignalSkillStatus'); 

export {}; // For Type definition purposes

 /**
  * SignalSkillStatus 
  * (Type): Inhibiting   
  * (Pass Condition): Skill status is IDLE  
  * (Description): Jibo should not fire if he is already doing a skill.
  * @private
  */
export class SignalSkillStatus extends InhibitingSignal {

    public init(): void { /* noop */ }
    
    public dispose(): void { /* noop */ }

    /**
     * Evaluates status of current skill name
     * Pass: IDLE
     * Fail: Anything else
     */
    public evaluate(): boolean {
        const skillState = this.parent.createState();
        
        if (skillState.skillName === SkillNames.IDLE) {
            log.debug("Passed: SkillStatus is " + skillState.skillName);
            return true;
        } else {
            log.info("Failed: SkillStatus is " + skillState.skillName);                
            return false;
        }
    }
}