import {Drive} from '../Drive';
import {ActionRuntime} from '../../common/ActionRuntime';
import {CircadianState} from 'jibo-common-types';


export {};

/**
 * A drive which checks the circadianGoalProvider's SleepState, and sets its ratePerMin to 0 if
 * Jibo is not awake.
 * @internal
 * @private
 */
export class WakingDrive extends Drive {

    private _wakingRatePerMin: number;
    constructor(private parent: ActionRuntime, name: string, ratePerMin: number = 0, public shouldCauseGoal = true) {
        super(name, ratePerMin, shouldCauseGoal);
        this._wakingRatePerMin = this.ratePerMin;
    }

    public update() {
        // check if awake. if not awake, set ratePerMin to 0. If awake, set to _daytimeRatePerMin
        let currentCircadianState = this.parent.createState().circadian;
        if (currentCircadianState === CircadianState.ALERT || currentCircadianState === CircadianState.RELAXED) { // TODO: Run this by Andrew.Stout
            this.ratePerMin = this._wakingRatePerMin;
        } else {
            this.ratePerMin = 0;
            this._value = 0; // reset drive value to 0 if not in waking state. This resets drive for after sleep, and prevents stale activation during sleep.
        }
        super.update();
    }

}
