import {Action} from '../Action';
import {ActionRuntime} from '../../common/ActionRuntime';
import {ActionResult, GoalFinishedStatus} from '../../common/Types';
import {SSWGoal} from '../../goal/goals/SSWGoal';
import {SkillNames} from "../../common/Utils";
import {CacheUtils} from 'jibo-cai-utils';

export {}; // Needed for type definitions

const findRoot = require('find-root');

const ROOT = findRoot(__filename);
const SOUNDS_ROOT = ROOT + '/resources/audio/';

const Sound = {
    ONTOUCH: SOUNDS_ROOT + `touch-on.m4a`,
    ONEXIT: SOUNDS_ROOT + `touch-off.m4a`
};

const DEFAULT_MILLISECONDS_TO_HOLD_TOUCH = 1000;
const TOUCH_RESET_TIME = 1000;

/**
 * @private
 */
export class HeadTouch extends Action {
    public static MILLISECONDS_TO_HOLD_TOUCH = 1000;
    private _canceled = false;

    /**
     * The last time jibo's head was touched.
     * @name jibo.globalEvents#_lastTouchTime
     * @private
     * @type {number}
     */
    private _lastTouchTime =-1;

    /**
     * Reset the duration needed to hold the head and quit the skill
     *  to the default value.
     * @method jibo.action#resetHoldToQuitTime
     */
    public static resetHoldToQuitTime() {
        HeadTouch.MILLISECONDS_TO_HOLD_TOUCH = DEFAULT_MILLISECONDS_TO_HOLD_TOUCH;
    }

    constructor(parent: ActionRuntime, private shouldQuitSkill:boolean) {
        super(parent, 'HeadTouch');
    }

    /**
     * Runs touch to stop action
     * @return {Promise<ActionResult>}
     */
    async runInternal(): Promise<ActionResult> {
        const promises: Promise<any>[] = [];

        const result = await new Promise<ActionResult>(resolve => {
            if (Date.now() - this._lastTouchTime > TOUCH_RESET_TIME) {
                promises.push(this._playSound(Sound.ONTOUCH));
            }

            this._canceled = false;
            this.parent.jibo.system.events.touchOff.waitFor(HeadTouch.MILLISECONDS_TO_HOLD_TOUCH)
                .then((data) => {
                    // The touch was released
                    resolve(ActionResult.FAILED);
                }).catch(timeout => {
                    // Touch was sustained for threshold time
                    if (this._canceled) {
                        resolve(ActionResult.CANCELED);
                    } else {
                        promises.push(this._playSound(Sound.ONEXIT));
                        this.log.info("stopping listen jibo via touch");
                        this.parent.jibo.analytics.track('Listen Stop', {type: 'touch', status: 'done'});
                        this.parent.jibo.jetstream.cancelAnyTurn();

                        if(this.shouldQuitSkill) {
                            this.parent.jibo.analytics.track('Global Stop', {type: 'touch', status: 'done'});
                            const sswGoal = new SSWGoal(this.parent, {
                                skillName: SkillNames.IDLE,
                                skillOptions: {}
                            }, `Hold Switch to Idle Goal`);

                            sswGoal.events.finished.on((result: GoalFinishedStatus)=> {
                                if (result === GoalFinishedStatus.SUCCEEDED) {
                                    resolve(ActionResult.SUCCEEDED);
                                } else {
                                    resolve(ActionResult.FAILED);
                                }
                            });

                            this.parent.goals.addGoal(sswGoal);
                        }
                        else {
                            resolve(ActionResult.SUCCEEDED);
                        }
                    }
                });
        });

        // Allow sounds to finish
        await Promise.all(promises);
        return result;
    }

    /**
     * Should be overridden by actions that want to respond to canceling
     */
    async cancelInternal(): Promise<any> {
        this._canceled = true;
    }

    /**
     * Play a sound through jibo's cached loader module and sound.
     * @method jibo.globalEvents~_playSound
     * @param {string} path to the file to be played.
     * @private
     */
    private async _playSound(path: string): Promise<void> {
        return new Promise<void>((resolve, reject) => {
            // if the global cache doesn't exist, the sound won't be there
            // for sure. We're probably in oobe-config, or another place
            // without a globally-initialized cache.
            if(!CacheUtils.initialized) {
                reject(new Error(`Global cache not initialized`));
                return;
            }
            const sound = this.parent.jibo.loader.cached(path, CacheUtils.GlobalCacheName);
            if (sound) {
                sound.play();
                resolve();
            }
            else {
                // Load the file first
                this.parent.jibo.loader.load({
                    type: 'sound',
                    id: path,
                    cache: CacheUtils.GlobalCacheName,
                    src: path,
                    complete: (err:Error, sound) => {
                        if (err) {
                            reject(err);
                            return;
                        }
                        sound.play();
                        // TODO: Probably should resolve after sound is done
                        resolve();
                    }
                });
            }
        });
    }
}
