import {Action} from './Action';
import {Goal} from '../goal/Goal';
import {ActionRuntime} from '../common/ActionRuntime';
import {ActionResult, GoalFinishedStatus, GoalProgressStatus} from '../common/Types';
import { log as parentLog } from './log';

const log = parentLog.createChild('GoalDrivenAction');


export {}; // For type definition purposes

/**
 * @description
 * Represents a goal and an action
 * to accomplish the goal.
 * @private
 */
export class GoalDrivenAction {

    public currentRunPromise: Promise<ActionResult> = null;

    constructor(public goal: Goal, public action: Action, private parent: ActionRuntime) {
    }

    /**
     * Takes the action that accomplishes the goal
     * and updates the status of the goal accordingly
     * @return {Promise<ActionResult>}
     */
    public async run(): Promise<ActionResult> {
        const failed = () => {
            log.info(`Action: '${this.action.name}' failed'`);
            if (this.goal.attempts >= this.goal.options.maxAttempts) {
                this.goal.setFinishedStatus(GoalFinishedStatus.FAILED);
                this.parent.goals.removeGoal(this.goal);
            } else {
                this.goal.setProgressStatus(GoalProgressStatus.ATTEMPTED);
            }
        };

        log.info(`Taking action: '${this.action.name}' to achieve goal '${this.goal.name}'`);
        this.goal.attempts++;
        this.currentRunPromise = this.action.run()
            .then(result => {
                log.info(`Completed action: '${this.action.name}' with result: '${result}'`);
                this.currentRunPromise = null;
                switch (result) {
                    case ActionResult.SUCCEEDED:
                        this.goal.setFinishedStatus(GoalFinishedStatus.SUCCEEDED);
                        // if the action succeeded, apply its motivational effects (if any)
                        this.parent.motivations.applyMotivationalEffects(this.action);
                        this.parent.goals.removeGoal(this.goal);
                        break;
                    case ActionResult.TIMEOUT:
                    case ActionResult.CANCELED:
                    case ActionResult.FAILED:
                        failed();
                        break;
                    default:
                        log.warn(`Action outcome '${result}' for action '${this.action.name}' unknown`);
                }
                return result;
            }).catch(error => {
                log.error(`Error running action ${this.action.name}: `, error);
                this.currentRunPromise = null;
                failed();
                return ActionResult.FAILED;
            });
        return this.currentRunPromise;
    }
}
