export interface EventResult<T> {
    promise: Promise<T>;
    stop(): void;
}

export interface EmitterLike {
    emit(event: string, ...args: any[]);
    on(event: string, listener: Function): EmitterLike;
    once(event: string, listener: Function): EmitterLike;
    removeListener(event: string, listener: Function): EmitterLike;
}

export interface EventLike<T> {
    on(handler: (data?: T) => void): this;
    removeListener(handler: (data?: T)=>void): this;
}

export type Handler<T> = (data?: T) => void;
export type Predicate<T> = (data?: T) => boolean;


function create<T>(predicate: Predicate<T>, addListener: (handler: Handler<T>)=>void, removeListener: (handler: Handler<T>)=>void, timeout = -1): EventResult<T> {
    let done = false;
    let eventHandler: (data:T)=>void;
    let timeoutHandle: NodeJS.Timer = null;

    return {
        promise: new Promise<T>((resolve, reject) => {
            if (timeout > 0) {
                timeoutHandle = setTimeout(() => {
                    if (!done) {
                        done = true;
                        removeListener(eventHandler);
                        timeoutHandle = null;
                        reject('TIMEOUT');
                    }
                }, timeout);
            }
            eventHandler = (data: T) => {
                if (!predicate || predicate(data)) {
                    if (!done) {
                        done = true;
                        removeListener(eventHandler);
                        if (timeoutHandle) {
                            clearTimeout(timeoutHandle);
                        }
                        resolve(data);
                    }
                }
            };
            addListener(eventHandler);
        }),

        stop: () => {
            if (!done) {
                done = true;
                removeListener(eventHandler);
                if (timeoutHandle) {
                    clearTimeout(timeoutHandle);
                }
            }
        }
    };
}

export class EventWaiter<T> {

    constructor(private predicate: Predicate<T>, private eventName: string, private eventEmitter: EmitterLike, private timeout = -1) {
    }

    start(): EventResult<T> {
        return create<T>(
            this.predicate,
            (handler) => this.eventEmitter.on(this.eventName, handler),
            (handler) => this.eventEmitter.removeListener(this.eventName, handler),
            this.timeout
        );
    }
}

export class TypedEventWaiter<T> {

    constructor(private predicate: Predicate<T>, private event: EventLike<T>, private timeout = -1) {
    }

    start(): EventResult<T> {

        return create<T>(
            this.predicate,
            (handler) => this.event.on(handler),
            (handler) => this.event.removeListener(handler),
            this.timeout
        );
    }
}
