// External
import { PresenceRecord, IdentificationSource } from "jibo-common-types";
import { Event } from 'jibo-typed-events';
// Internal
import { log as parentLog } from '../../log';
import { FiringSignal } from '../FiringSignal';


export {}; // For Type definition purposes

const log = parentLog.createChild('SignalIDAcquired');

 /**
  * SignalIDAcquired
  * (Type): Firing
  * (Handles): IDAcquired events
  * (Fire Condition): Will immediately fire once it receives an IDAcquired event that is of kind PERSON (aka face not speech)
  * @private
  */
export class SignalIDAcquired extends FiringSignal {

    // Emitted an event when a face ID occurs
    public faceIDAcquired = new Event<string>("Face ID Acquired");

    public init(): void {
        this.parent.jibo.lps.identity.events.idAcquired.on(this.handleIDAcquiredBind);
    }

    public dispose(): void {
        this.parent.jibo.lps.identity.events.idAcquired.removeListener(this.handleIDAcquiredBind);
    }

    // Internal bind function
    private handleIDAcquiredBind = (data) => this.handleIDAcquired(data);

    /**
     * Called whenever an ID is acquired
     */
    private handleIDAcquired(presence: PresenceRecord): void {
        log.debug(`ID acquired ${presence.name}. By source: ${presence.identificationSource}`);
        // Fire only if the ID is from visual identification and not from "Hey Jibo" audio
        if (presence.identificationSource === IdentificationSource.FACE) {
            this.faceIDAcquired.emit(presence.name);
        }
    }
}