import { log as parentLog } from '../log';
import * as _ from 'lodash/lodash.min';


const FACE_ANGLE_THRESH = Math.PI / 8;
const AWAIT_TIMEOUT = 3; // seconds!

const EXPRESSION_TIMEOUT = 10*1000; // milliseconds!

const OWNER_IDENTIFIER = 'AttentionCommand';

export enum Outcome {
    Result = 'Result',
    Face = 'Face',
    Timeout = 'Timeout',
    Motion = 'Motion'
}

interface OutcomeWithData {
    outcome: Outcome;
    data?: any;
}

type AngleCalculator = (point1: Point3, point2: Point3) => number;

/**
 * A face object combined with an angle (for example, an angle offset from a reference location)
 * @interface FaceWithAngle
 */
interface FaceWithAngle {
    face: any; // TODO: Is there a better type for this?
    angle: number;
}
/**
 * Checks to see if there are visible faces close to a given HJ location
 * @param {Point3} position of HJ
 * @return {Object|null} returns a face if one was found
 */
function faceNearReference(position: Point3, actionRuntime: ActionRuntime, angleCalculator: AngleCalculator): FaceWithAngle | null {
    let bestAngle = Number.MAX_SAFE_INTEGER;
    let bestFace = null;
    actionRuntime.jibo.lps.identity.getVisibleFaces().forEach((face) => {
        if (face.in_fov) {
            const angle = angleCalculator(position, face.position);
            if (angle < bestAngle) {
                bestAngle = angle;
                bestFace = face;
            }
        }
    });
    parentLog.info(`Initial face: `, position, bestFace ? bestFace.id : null);
    if (bestFace && bestAngle < FACE_ANGLE_THRESH) {
        return {face: bestFace, angle: bestAngle};
    }
}


/**
 * Calculates the 2D angle between two 3D vectors when their Z value is set to 0
 * @param {Point3} point1
 * @param {Point3} point2
 * @return {number}
 * @private
 */
function angleXY(point1: Point3, point2: Point3): number {
    const p1 = {x: point1.x, y: point1.y, z: 0};
    const p2 = {x: point2.x, y: point2.y, z: 0};
    return angle3d(p1, p2);
}

/**
 * Calculates the angle between two 3d vectors
 * @param {Point3} entity1
 * @param {Point3} entity1
 * @return {number}
 * @private
 */
function angle3d(point1: Point3, point2: Point3): number {
    const dotProduct = point1.x*point2.x + point1.y*point2.y + point1.z*point2.z;
    const length1 = Math.sqrt(point1.x*point1.x + point1.y*point1.y + point1.z*point1.z);
    const length2 = Math.sqrt(point2.x*point2.x + point2.y*point2.y + point2.z*point2.z);
    if (length1 === 0 || length2 === 0) {
        // This is undefined but I'd rather get a big number than a NaN
        return Math.PI;
    } else {
        return Math.acos(dotProduct/(length1*length2));
    }
}

/**
 * @private
 */
export enum AngleCalculatorType { XY, XYZ }

/**
 * A state that handles awaiting a face
 * @private
 */
export class YesNoState extends SMState {

    protected _yesState: SMState;
    protected _noState: SMState;

    constructor(sm: StateMachine, name: string, private transitionNames = ['Yes', 'No']) {
        super(sm, name);
    }

    installTransitions(yesState: SMState, noState: SMState) {
        this._yesState = yesState;
        this._noState = noState;
        this.addInternalTransition(this.transitionNames[0], this._yesState);
        this.addInternalTransition(this.transitionNames[1], this._noState);
    }
}

/**
 * A state that handles attending to a location
 * @private
 */
export class AttendToState extends SMState {

    private _handle: AcquireHandle;
    private log = parentLog.createChild('AttendToState');

    constructor(sm: StateMachine, private actionRuntime: ActionRuntime, name: string, public floorZ: boolean = true) {
        super(sm, name);
        this.onEntry = this._onEntry.bind(this);

        this.onStop = () => {
            if (this._handle) {
                const handle = this._handle;
                this._handle = null;
                return handle.cancel();
            } else {
                return Promise.resolve();
            }
        };
    }

    protected overrideLocation(data: AcquireOptions) {
        return data;
    }

    async _onEntry(transition: Transition, data: AcquireOptions) { // TODO: NEED BETTER TYPE SAFETY
        const jibo = this.actionRuntime.jibo;
        data = this.overrideLocation(data);

        if (!data || !((data.entity && data.entity.id) || (data.position && (data.position.x !== undefined)))) {
            this.log.error('Bad AttendTarget data in AttendToState. SM trace: ', this.sm.traceToString());
            throw new Error(`${this.name}: Bad AttendTarget data ${JSON.stringify(data)}`);
        }

        // make call to expression system for orient to position
        let pos:{x:number, y:number, z:number} = null;

        if(data.position) {
            pos = {
                x: data.position.x,
                y: data.position.y,
                z: this.floorZ ? Math.max(-0.1, data.position.z) : data.position.z
            };
        }

        try {
            this._handle = await timeout(jibo.expression.acquireTarget({position: pos, entity: data.entity}),
                EXPRESSION_TIMEOUT, {log: this.log, logMessage: 'jibo.expression.acquireTarget'});
            if (!this._handle) {
                return ResultStatus.TIMEOUT;
            }
            return await timeout(this._handle.promise, EXPRESSION_TIMEOUT, {
                log: this.log,
                logMessage: `acquireTarget.handle.promise`,
                timeoutValue:ResultStatus.TIMEOUT
            });
        } catch(e) {
            throw e;
        } finally {
            this._handle = null;
        }
    }
}


/**
 * A state that handles reacting by playing a flow
 * @private
 */
export class FlowState extends SMState {

    private _flowHandle: any;
    private log = parentLog.createChild('FlowState');

    constructor(sm: StateMachine, private actionRuntime: ActionRuntime, name: string, private flow: any) {
        super(sm, name);
        this.onEntry = this._onEntry.bind(this);

        this.onStop = () => {
            if (this._flowHandle) {
                this._flowHandle.stop();
                this._flowHandle = null;
            }
        };
    }

    async _onEntry(trans, data) {
        const jibo = this.actionRuntime.jibo;

        if (!this.flow) {
            this.log.warn(`Skipping flow: '${this.name}'`);
        } else {
            this.log.info(`Playing flow: '${this.name}'`);

            const result = {};

            const options = {
                result,
                assetPack: 'jibo/node_modules/jibo-action-system', // eww.
                enableLogging: false,
            };

            try {
                await PromiseUtils.promisify<any>(h => {
                    this._flowHandle = jibo.flow.run(this.flow, options, h);
                });
            } catch(e) {
                throw e;
            } finally {
                this._flowHandle = null;
            }
        }
        // someday it would be nice to be able to return the flow result as well as whatever data was passed in.
        // that would require standardized formatting and processing of all states. Which is a good idea, but time-consuming.
        return data; // pass through whatever data you got in.
    }
}

/**
 * @private
 */
export class DoneState extends SMState {

    constructor(sm: StateMachine, name:string = 'Done', data?:any) {
        super(sm, name);
        this.onEntry = () => {
            this.sm.stop(data);
        };
    }
}


/**
 * @private
 */
export class PersonVisibleNearReferenceState extends YesNoState {

    referencePosition: Point3;

    constructor(sm: StateMachine, public actionRuntime: ActionRuntime, angleCalculator: AngleCalculatorType) {
        super(sm, 'Is person visible?');
        this.onEntry = () => {
            if (!this.referencePosition) {
                throw new Error(`${this.name}: Missing reference position`);
            }
            const calculator = angleCalculator === AngleCalculatorType.XY ? angleXY : angle3d;
            const face = faceNearReference(this.referencePosition, actionRuntime, calculator);
            if (face) {
                this.transitionTo(this._yesState, face.face);
            } else {
                this.transitionTo(this._noState, {position: this.referencePosition});
            }
        };
    }

    setReferencePosition(referencePosition: Point3){
        this.referencePosition = referencePosition;
    }
}


/**
 *
 *
 * @interface ReferenceLocationWithAlternate
 */
export interface ReferenceLocationWithAlternate {
    hjloc: Point3;
    altHJloc?: Point3;
}

/**
 * New approach to choosing orientation point that checks for a face near reference for both
 * HJloc and altHJloc reference points. Chooses the better match, or primary hj location if no
 * face information is available.
 * @export
 * @class ChooseOrientationPointState
 * @extends {YesNoState}
 */
export class ChooseOrientationPointState extends YesNoState {

    referencePositions: ReferenceLocationWithAlternate;

    private log = parentLog.createChild('ReferenceLocationWithAlternate');

    constructor(sm: StateMachine, public actionRuntime: ActionRuntime, private angleCalculator: AngleCalculatorType) {
        super(sm, 'Choose Orientation Point', ['faceState', 'hjLocState']);
    }

    onEntry = () => {
        let faceState = this._yesState;
        let hjlocState = this._noState;
        if (!this.referencePositions) {
            throw new Error(`${this.name}: Missing reference positions`);
        }
        const calculator = this.angleCalculator === AngleCalculatorType.XY ? angleXY : angle3d;
        // get face & angle for primary
        let hjface = faceNearReference(this.referencePositions.hjloc, this.actionRuntime, calculator);

        // check face near reference for both HJloc and altHJloc
        // if alt exists, get face & angle for that, do both logic
        if (this.referencePositions.altHJloc) {
            this.log.debug(`have altHJloc`);
            let altHJface = faceNearReference(this.referencePositions.altHJloc, this.actionRuntime, calculator);
            if (!hjface && !altHJface) {
                // no face at either location. take best guess--the HJ loc. (could also do bias for movement like above)
                this.log.debug(`no face at either location. take best guess--the HJ loc.`);
                return this.transitionTo(hjlocState, {position: this.referencePositions.hjloc});
            } else if (hjface && altHJface) {
                // both have faces. take the better match.
                this.log.debug(`both have faces. take the better match.`);
                if (altHJface.angle < hjface.angle) {
                    this.log.debug(`altHJ angle is smaller`);
                    return this.transitionTo(faceState, altHJface.face);
                } else {
                    this.log.debug(`primary HJ angle is smaller`);
                    return this.transitionTo(faceState, hjface.face);
                }
            } else { // only one has face. take the one with face
                if (hjface) {
                    this.log.debug(`only primary HJ loc has face.`);
                    return this.transitionTo(faceState, hjface.face);
                } else {
                    this.log.debug(`only altHJloc has face.`);
                    return this.transitionTo(faceState, altHJface.face);
                }
            }
        } else {
            this.log.debug(`no altHJloc`);
            // else do the original thing
            if (hjface) {
                this.log.debug(`found face near HJ`);
                return this.transitionTo(faceState, hjface.face);
            } else {
                // no face, no altHJ
                this.log.debug(`no face near HJ, just using HJ location`);
                return this.transitionTo(hjlocState, {position: this.referencePositions.hjloc});
            }
        }

    }

    setReferencePositions(referencePositions: ReferenceLocationWithAlternate){
        this.referencePositions = _.cloneDeep(referencePositions);
    }

}


/**
 * Another possible approach for choosing orientation point, which biases for movement.
 * If both hj and alt exist and no face at primary hjloc, choose the one which is farther from
 * the current robot orientation.
 * @export
 * @class ChooseOrientationPointStateBiasForMovement
 * @extends {YesNoState}
 */
export class ChooseOrientationPointBiasForMovementState extends YesNoState {

    referencePositions: ReferenceLocationWithAlternate;

    private log = parentLog.createChild('ReferenceLocationWithAlternate');

    constructor(sm: StateMachine, public actionRuntime: ActionRuntime, private angleCalculator: AngleCalculatorType) {
        super(sm, 'Choose Orientation Point', ['Found Face', 'No Face, use audio localization']);
    }

    onEntry = () => {
        let faceState = this._yesState;
        let hjlocState = this._noState;
        if (!this.referencePositions) {
            throw new Error(`${this.name}: Missing reference positions`);
        }
        const calculator = this.angleCalculator === AngleCalculatorType.XY ? angleXY : angle3d;
        // get face & angle for primary
        let hjface = faceNearReference(this.referencePositions.hjloc, this.actionRuntime, calculator);

        // if no face at primary HJloc, orient to loc that is farther from current orientation
        if (!hjface && !!this.referencePositions.altHJloc) {
            this.log.debug(`no face at primary hjloc and altHJloc exists, comparing angles`);
            let hjangle = calculator(this.actionRuntime.jibo.expression.features.head.direction, this.referencePositions.hjloc);
            let althjangle = calculator(this.actionRuntime.jibo.expression.features.head.direction, this.referencePositions.altHJloc);
            if (althjangle > hjangle) {
                // transition to with althjloc
                this.log.debug(`altHJloc has higher angle, orienting there`);
                return this.transitionTo(hjlocState, {position: this.referencePositions.altHJloc});
            } else {
                this.log.debug(`primary HJloc has higher angle, orienting there`);
                return this.transitionTo(hjlocState, {position: this.referencePositions.hjloc});
            }
        } else if (hjface) {
            // transition to hjface.face.position
            this.log.debug(`face exists near primary HJ loc, orienting to that`);
            return this.transitionTo(faceState, hjface.face);
        } else {
            // else transition to hjloc
            this.log.debug(`no face, no altHJloc, orienting to primary HJloc`);
            return this.transitionTo(hjlocState, {position: this.referencePositions.hjloc});
        }
    }

    setReferencePositions(referencePositions: ReferenceLocationWithAlternate){
        this.referencePositions = _.cloneDeep(referencePositions);
    }

}



/**
 * @private
 */
export class WaitForResults extends SMState {

    constructor(private hjOrient: HJOrient) {
        super(hjOrient.sm, 'Waiting for results');
        this.onEntry = () => {
            // These promises get resolved when results are received
            return Promise.race(this.hjOrient.resultWaiters.map(e => e[1].promise));
        };
    }
}

/**
 * @private
 */
export class WaitForSignals extends SMState {

    private _rcvResults: SMState;
    private _faceFound: SMState;

    private _attendHandle: AwaitFaceHandle;

    constructor(private hjOrient: HJOrient) {
        super(hjOrient.sm, 'Waiting for face or signal');
        this.onEntry = this._onEntry.bind(this);

        this.onExit = () => {
            if (this._attendHandle) {
                this._attendHandle.cancel();
                this._attendHandle = null;
            }
        };
    }

    installTransitions(rcvResults: SMState, faceFound: SMState) {
        this._rcvResults = rcvResults;
        this._faceFound = faceFound;
        this.addInternalTransition('Received results', this._rcvResults);
        this.addInternalTransition('Found face', this._faceFound);
    }

    _onEntry() {
        this.hjOrient.log.debug('HJOrient waiting for signals');
        // These promises get resolved when results are received
        let promises: Promise<OutcomeWithData>[] = this.hjOrient.resultWaiters
            .map(e => e[1].promise.then(() => {
                this.hjOrient.log.debug(`result waiter resolved`);
                return {outcome: Outcome.Result};
            }));
        promises.push(this.waitForFace());

        Promise.race(promises).then((outcome) => {
            this.hjOrient.log.debug(`hjOrient got outcome`);
            if (outcome.outcome === Outcome.Face) {
                this.transitionTo(this._faceFound, outcome.data);
            } else if (outcome.outcome === Outcome.Result) {
                this.transitionTo(this._rcvResults);
            } else if (outcome.outcome === Outcome.Timeout) {
                this.hjOrient.log.warn(`Wait for signals timed out.`);
                this.transitionTo(this._rcvResults);
            } else {
                throw new Error(`Unknown outcome: '${outcome}'`);
            }
        });
    }

    async waitForFace(): Promise<OutcomeWithData> {
        const jibo = this.hjOrient.parent.jibo;
        // this triggers an lps.demandDetect
        const awaitPromise = jibo.expression.awaitFace({
            timeout: AWAIT_TIMEOUT
        });
        this._attendHandle = await timeout(awaitPromise, EXPRESSION_TIMEOUT, {
            log: this.hjOrient.log,
            logMessage: `jibo.expression.awaitFace`
        });
        if (!this._attendHandle) {
            return {outcome: Outcome.Timeout};
        }
        const face  = await timeout(this._attendHandle.promise, EXPRESSION_TIMEOUT, {
            log: this.hjOrient.log,
            logMessage: `awaitFace.attendHandle.promise`
        });

        if (face && face.status === ResultStatus.SUCCEEDED) {
            return {outcome: Outcome.Face, data: face};
        } else {
            return {outcome: Outcome.Timeout};
        }
    }
}


/**
 * @private
 */
export class HaveReceivedResultState extends YesNoState {

    constructor(private hjOrient: HJOrient) {
        super(hjOrient.sm, 'Have received result');
        this.onEntry = () => {
            if (this.hjOrient.haveReceivedResult) {
                this.transitionTo(this._yesState);
            } else {
                this.transitionTo(this._noState);
            }
        };
    }
}


/**
 * Threshold for lighting quality below which we skip trying to find a face.
 * @private
 */
const LIGHTING_QUALITY_THRESHOLD = 0.25; // an initial guess at a good threshold. This will need to be tuned...

/**
 * @private
 */
export class LightingGoodState extends YesNoState {

    log = parentLog.createChild('LightingGoodState');

    constructor(sm: StateMachine, public actionRuntime: ActionRuntime) {
        super(sm, 'Is lighting good?');
        this.onEntry = () => {
            const lightQual = this.actionRuntime.jibo.lps.lightingQuality;
            this.log.info(`lighting quality: `, lightQual);
            if (lightQual >= LIGHTING_QUALITY_THRESHOLD) {
                this.transitionTo(this._yesState);
            } else {
                this.transitionTo(this._noState);
            }
        };
    }
}

/**
 * A state that handles awaiting a face
 * @private
 */
export class PickNextLocationState extends YesNoState {

    constructor(search: SearchAction) {
        super(search.sm, 'Is another search location available?');
        this.onEntry = () => {
            if (search.searchCandidates.length) {
                const nextLoc = search.searchCandidates.shift();
                this.transitionTo(this._yesState, nextLoc);
            } else {
                this.transitionTo(this._noState);
            }
        };
    }
}

/**
 * A state that handles awaiting a face
 * @private
 */
export class AwaitFaceState extends SMState {

    private _faceHandle: AwaitFaceHandle;
    private _faceFoundState: SMState;
    private _timeoutState: SMState;
    private _motionDetectedState: SMState;

    constructor(private parent: SearchAction, name: string, private timeOut = -1) {
        super(parent.sm, name);
        this.onEntry = this._onEntry.bind(this);

        this.onExit = () => {
            if (this._faceHandle) {
                this._faceHandle.cancel();
                this._faceHandle = null;
            }
        };
    }

    installTransitions(faceFoundState: SMState, timeoutState: SMState, motionDetectedState: SMState) {
        this._faceFoundState = faceFoundState;
        this._timeoutState = timeoutState;
        this._motionDetectedState = motionDetectedState;

        this.addInternalTransition('Face found', this._faceFoundState);
        this.addInternalTransition('Timeout', this._timeoutState);
        this.addInternalTransition('Motion detected', this._motionDetectedState);
    }

    createMotionDetectionPromise(): Promise<OutcomeWithData> {
        return new Promise<OutcomeWithData>(resolve => {
            // TODO implement
        });
    }

    async _onEntry() {
        const jibo = this.parent.parent.jibo;

        this._faceHandle = await timeout(jibo.expression.awaitFace({timeout: this.timeOut}),
            EXPRESSION_TIMEOUT, {log: this.parent.log, logMessage: `jibo.expression.awaitFace`});
        let promises: Promise<OutcomeWithData>[] = [];
        if (this._faceHandle) {
            promises.push(
                timeout(this._faceHandle.promise,
                    EXPRESSION_TIMEOUT,
                    {log: this.parent.log, logMessage: `awaitFace.handle.promise`} )
                .then(face => {
                    if (face && face.status === ResultStatus.SUCCEEDED) {
                        return {outcome: Outcome.Face, data: face};
                    } else {
                        return {outcome: Outcome.Timeout};
                    }
                }).catch((e) => {
                    this.parent.log.error(`AwaitFace: `, e);
                    return { outcome: Outcome.Timeout }; // Return timeout here just to return something
                }).then((data) => {
                    this._faceHandle = null;
                    return data;
                })
            );
        } else {
            promises.push(Promise.resolve({outcome: Outcome.Timeout}));
        }
        promises.push(this.createMotionDetectionPromise());
        try {
            const outcome = await Promise.race(promises);
            if (outcome.outcome === Outcome.Face) {
                this.transitionTo(this._faceFoundState, outcome.data);
            } else if (outcome.outcome === Outcome.Timeout) {
                this.transitionTo(this._timeoutState);
            } else if (outcome.outcome === Outcome.Motion) {
                this.transitionTo(this._motionDetectedState, outcome.data);
            } else {
                this.parent.log.error(`Await face, invalid outcome: `, outcome);
                this.transitionTo(this._timeoutState);
            }
        } catch (error) {
            this.parent.log.error(`Await face, error: `, error);
            this.transitionTo(this._timeoutState);
        }
    }
}




/**
 * @private
 */
export class OrientToStandard extends SMState {

    constructor(sm: StateMachine, actionRuntime: ActionRuntime) {
        super(sm, 'Orient to standard location');
        this.onEntry = () => {
            return actionRuntime.jibo.expression.centerRobot({
                requestor: OWNER_IDENTIFIER,
                centerGlobally: true
            });
        };
    }
}



/**
 * @private
 */
export class AttendToFixedState extends AttendToState {

    constructor(sm: StateMachine, actionRuntime: ActionRuntime, name: string, private standard: AcquireOptions) {
        super(sm, actionRuntime, name);
    }

    protected overrideLocation(data: AcquireOptions) {
        return this.standard;
    }
}
