import {Log} from './log';

export {}; // For type definition purposes

/**
 * @private
 */
export const SkillNames = {
    IDLE: '@be/idle',
    GREETINGS: '@be/greetings',
    SETTINGS: '@be/settings',
    CLOCK: '@be/clock',
    TUTORIAL: '@be/tutorial',
    FIRST_CONTACT: '@be/first-contact',
    SURPRISES: '@be/surprises',
};

/**
 * @private
 */
export class SkillUtils {

    /**
     * Determines whether a skill relaunch request was for an error skill
     * @param {object} skillData
     * @return {boolean}
     */
    static isErrorSkill(skillData: any): boolean {
        return skillData.nlu &&
            skillData.nlu.entities.skill === SkillNames.SETTINGS &&
            skillData.nlu.entities.errorId;
    }

    /**
     * Determines whether a skill relaunch request was for the timer/alarm skill
     * @param {object} skillData
     * @return {boolean}
     */
    static isAlarmTimerSkill(skillData: any): boolean {
        return skillData.nlu &&
            skillData.nlu.entities.skill === SkillNames.CLOCK &&
            ((skillData.nlu.entities.domain === 'alarm' && skillData.nlu.intent === 'finished') ||
            (skillData.nlu.entities.domain === 'timer' && skillData.nlu.intent === 'finished'));
    }
}

/**
 * @private
 *
 * @param {number} value
 * @param {number} min
 * @param {number} max
 * @returns {number}
 */
export function constrainToBounds(value: number, min: number, max: number): number {
    return Math.max(min, Math.min(max, value));
}

/**
 * A Double Map uses two ordered keys to retrieve a value
 * @private
 * @internal
 */
export class DoubleMap<A, B, C> {

    private map = new Map<A, Map<B, C>>();

    /**
     * Insert a value into map
     * @param {A} key1 - First key
     * @param {B} key2 - Second key
     * @param {C} value - Value to insert
     */
    set(key1: A, key2: B, value: C) {
        let second = this.map.get(key1);
        if (!second) {
            second = new Map<B, C>();
            this.map.set(key1, second);
        }
        second.set(key2, value);
    }

    /**
     * Get a value from map
     * @param {A} key1 - First key
     * @param {B} key2 - Second key
     * @returns {C} The value or undefined if none found
     */
    get(key1: A, key2: B): C {
        let second = this.map.get(key1);
        if (!second) {
            return undefined;
        }
        return second.get(key2);
    }
}


// this is copied from jibo-embodied-dialog. Should probably get moved to cai-utils...
export interface TimeoutOptions<T> {
  log?: Log;
  logMessage?: string;
  timeoutValue?: T;
}

export function timeout<T>(pr: Promise<T>, timeoutTimeMs: number, options: TimeoutOptions<T> = {}): Promise<T> {
  return new Promise<T>((resolve, reject) => {
    let timeout = setTimeout(() => {
      if (options.log) {
        let msg = `Timeout of ${timeoutTimeMs} ms occurred`;
        if (options.logMessage) {
          msg += `. ${options.logMessage}`;
        }
        options.log.warn(msg);
      }
      resolve(options.timeoutValue);
    }, timeoutTimeMs);

    pr.then((data) => {
      clearTimeout(timeout);
      resolve(data);
    }).catch(e => {
      clearTimeout(timeout);
      reject(e);
    });
  });
}
