import {ActionRuntime} from '../../common/ActionRuntime';
import {Goal} from '../Goal';
import {AnimationGoalData, GoalPriorityType} from '../../common/Types';
import {GoalPriority} from "../GoalPriority";

export {}; // For Type definition purposes

/**
 * @private
 */
export class AnimationGoal extends Goal {

    static getName(data: AnimationGoalData): string {
        let name = `Play Animation Goal [`;
        name += (data.category) ? `cat: ${data.category}]` : `name: ${data.name}]`;
        return name;
    }

    constructor(parent: ActionRuntime, public data: AnimationGoalData, goalPriority?: GoalPriorityType) {
        super(parent, AnimationGoal.getName(data), {
            priority: GoalPriority.Animation,
            criteria: data.criteria,
            priorityType: goalPriority
        });
    }
}
