// External
import { CircadianState } from 'jibo-common-types';
// Internal
import { log as parentLog } from '../../log';
import { InhibitingSignal } from '../InhibitingSignal';


export {}; // For Type definition purposes

const log = parentLog.createChild('SignalJiboStatus');

/**
 * SignalJiboStatus
 * (Type): Inhibiting
 * (Pass Condition): Sleep State is AWAKE
 * (Description): Jibo should be AWAKE to do proactive behavior.
 * @private
 */
export class SignalJiboStatus extends InhibitingSignal {

    public init(): void { /* noop */ }

    public dispose(): void { /* noop */ }

    /**
     * Evaluates status of Jibo's circadian state
     * Pass: ALERT
     * Fail: Anything else
     */
    public evaluate(): boolean {
        const jiboState = this.parent.createState();

        if (jiboState.circadian === CircadianState.ALERT || jiboState.circadian === CircadianState.RELAXED) {
            log.debug("Passed: Jibo is " + jiboState.circadian);
            return true;
        } else {
            log.info("Failed: Jibo is " + jiboState.circadian);
            return false;
        }
    }
}