import {Action} from '../Action';
import {ActionRuntime} from '../../common/ActionRuntime';
import {ActionResult, Status} from '../../common/Types';
import {HeadTouch} from './HeadTouch';

/**
 * @private
 */
export class SSWAction extends Action {

    constructor(parent: ActionRuntime, private skillName: string, private skillData: any) {
        super(parent, `Skill Switch Action: '${skillName}'`);
    }

    protected async runInternal(): Promise<ActionResult> {
        // Here we wait one tick before switching skills
        await new Promise(resolve => process.nextTick(resolve));

        // Restore the default value of head touch to quit
        HeadTouch.resetHoldToQuitTime();

        if (!this.parent.skillSwitcher) {
            this.log.error(`No installed skill switcher`);
            return ActionResult.FAILED;
        } else {
            const status = await this.parent.skillSwitcher(this.skillName, this.skillData);
            switch (status) {
                case Status.SUCCEEDED:
                    return ActionResult.SUCCEEDED;
                case Status.FAILED:
                    return ActionResult.FAILED;
                default: {
                    this.log.error(`Unknown Skill Switch outcome: '${status}'`);
                    return ActionResult.FAILED;
                }
            }
        }
    }

    protected async cancelInternal(): Promise<any> {
        return Promise.resolve();
    }
}

export {}; // Needed for type definitions
