import {EventContainer, Event} from 'jibo-typed-events';
import {CircadianState} from 'jibo-common-types';
import {Goal} from '../goal/Goal';


/**
 * Defines a set of events that the action system might emit. These will be of a general nature
 * as opposed to the more specific events defined on goal objects for example
 * @class ActionEvents
 * @memberof jibo.action
 * @property {Event} oriented - Event emitted when Jibo is done orienting towards a lookat target: `Jibo has oriented towards target`
 * @property {Event<jibo.action.goal.Goal>} goalAdded - Goal was added to system: `Goal Created`
 * @property {Event} skillChange - Skill changed from old skill to new skill [oldSkillName newSkillName]
 * @property {Event<CircadianState>} circadianChange - Circadian state changed
 * @property {Event<boolean[]>} headPat - A head pat event happened which is not meant to stop a skill
 * @property {Event<boolean[]>} secondhandTouchStop - A head touch event which has not been used by the action system
 * @internal
 * @private
 */
export class ActionEvents extends EventContainer {

    oriented = new Event(`Jibo has oriented towards target`);
    goalAdded = new Event<Goal>('Goal Created');
    headPat = new Event<boolean[]>(`Jibo's head was touched in non-exit`);
    skillChange = new Event<[string, string]>(`Skill changed`);
    circadianChange = new Event<CircadianState>(`Circadian state changed`);
    secondhandTouchStop = new Event<boolean[]>('Head touch was not used by action system.');

    constructor() {
        super();
    }
}

/**
 * Defines a set of events that the action system might emit. These will be of a general nature
 * as opposed to the more specific events defined on goal objects for example
 * @class PublicActionEvents
 * @memberof jibo.action
 * @property {boolean[]} headPat - A head pat event happened which is not meant to stop a skill
 * @property {Event<CircadianState>} circadianChange - Circadian state changed
 * @property {Event<boolean[]>} secondhandTouchStop - A head touch event which has not been used by the action system
 * @intdocs
 */
export class PublicActionEvents extends EventContainer {

    headPat = this.events.headPat;
    circadianChange = this.events.circadianChange;
    secondHandTouchStop = this.events.secondhandTouchStop;

    /**
     * @private
     * @internal
     */
    constructor(private events: ActionEvents) {
        super();
    }
}