// External
import { PartOfDayTimes, PartOfDayBasic, PartOfDayDetail, TimeUtils } from 'jibo-cai-utils';
// Internal
import { PartOfDay } from '../../../common/Types';
import { log as parentLog } from '../../log';
import { InhibitingSignal } from '../InhibitingSignal';


export {}; // For Type definition purposes

const log = parentLog.createChild('SignalRateLimiterStatus');

let partOfDayProperties = {
    'MORNING': {
        'EARLY': { index: 2,  weight: { weekday: 0,    weekend: 0 }, maxTriggers: null},    // 4:45am
        'MID':   { index: 3,  weight: { weekday: 0.15, weekend: 0.14 }, maxTriggers: null}, // 6:45am
        'LATE':  { index: 4,  weight: { weekday: 0.10, weekend: 0.14 }, maxTriggers: null}, // 10:00am
    },
    'AFTERNOON': {
        'EARLY': { index: 5,  weight: { weekday: 0.12, weekend: 0.16 }, maxTriggers: null}, // 12:00pm
        'MID':   { index: 6,  weight: { weekday: 0.13, weekend: 0.14 }, maxTriggers: null}, // 2:00pm
        'LATE':  { index: 7,  weight: { weekday: 0.17, weekend: 0.15 }, maxTriggers: null}, // 4:00pm
    },
    'EVENING': {
        'EARLY': { index: 8,  weight: { weekday: 0.19, weekend: 0.15 }, maxTriggers: null}, // 6:00pm
        'MID':   { index: 9,  weight: { weekday: 0.08, weekend: 0.06 }, maxTriggers: null}, // 8:00pm
        'LATE':  { index: 10, weight: { weekday: 0.06, weekend: 0.06 }, maxTriggers: null}, // 9:00pm
    },
    'NIGHT': {
        'EARLY': { index: 11, weight: { weekday: 0, weekend: 0 }, maxTriggers: null}, // 10:00pm
        'MID':   { index: 0,  weight: { weekday: 0, weekend: 0 }, maxTriggers: null}, // 12:00am
        'LATE':  { index: 1,  weight: { weekday: 0, weekend: 0 }, maxTriggers: null}, // 2:00am
    }
};

// TODO: Move this into unit test
// Check that weights sum close to ~1.0
let weekdayWeightTotal = 0;
let weekendWeightTotal = 0;
PartOfDayTimes.forEach(partOfDayTime => {
    const { basic, detail } = partOfDayTime.pod;
    weekdayWeightTotal += partOfDayProperties[basic][detail].weight.weekday;
    weekendWeightTotal += partOfDayProperties[basic][detail].weight.weekend;
});
const weekdayDiff = Math.abs(1.0 - weekdayWeightTotal);
const weekendDiff = Math.abs(1.0 - weekendWeightTotal);
if (weekdayDiff > Number.EPSILON || weekendDiff >  Number.EPSILON) {
    throw new Error(`The sum of weights across the day does not sum to 1.0; Weekday: ${weekdayWeightTotal} Weekend: ${weekendWeightTotal}`);
}

/**
 * SignalRateLimiterStatus
 * (Type): Inhibiting
 * (Pass Condition): When we have not recently triggered and also have not surpassed our PartOfDay limit and daily limit.
 * (Description): Enforces a minimum time of X milliseconds before ever attempting another proactive request (RECENT_TRIGGER_EXPIRY_MS) 
 * Limit on total maximum proactive requests in a day (MAX_TRIGGERS_PER_DAY_LIMIT)
 * This daily limit is distributed across the whole day, which avoids (for example) using up all triggers in the morning.
 * @private
 */
export class SignalRateLimiterStatus extends InhibitingSignal {

    public static MAX_TRIGGERS_PER_DAY_LIMIT = 50; // 50 triggers max per day

    public static MAX_TRIGGERS_PER_HOUR_RATE = 10; // 10 triggers max per hour

    public static ROLLOVER_PROPORTION = 0.50; // 50% of remaining triggers from last PartOfDay can rollover 

    public static RECENT_TRIGGER_EXPIRY_MS = 500; // 500 ms

    // Timestamp of last proactive trigger request sent
    private lastTriggerMs: number = -1;

    // Budget for daily trigger limit
    private dailyTriggerBudget: number = SignalRateLimiterStatus.MAX_TRIGGERS_PER_DAY_LIMIT;

    // Array of trigger budgets across parts of the day
    private partOfDayTriggerBudget: number[] = [];

    // Timeouts drive when the next part of the day occurs.
    public timeoutHandle = null;
    public timeoutCallback = null;

    /** 
     * Init
     */
    public init(): void {
        this.calcMaxTriggersPartOfDay();
        this.reset();
        this.createNextPartOfDayTimeout();
    }

    /** 
     * Dispose
     */
    public dispose(): void {
        // Clear any existing timeouts
        if (this.timeoutHandle) {
            this.parent.jibo.timer.clearTimeout(this.timeoutHandle);
            this.timeoutHandle = null;
        }
    }

    /** 
     * Evaluate checks recency, PartOfDay limit, and daily limit
     */
    public evaluate(): boolean {
        return this.evaluateTriggerRecency() &&
            this.evaluatePartOfDayLimit() &&
            this.evaluateDailyLimit();
    }

    /**
     * Called when a proactive trigger request is sent to jetstream
     */
    public addTriggerEvent(timestampMs: number = Date.now()): void {
        // Set last trigger timestamp
        this.lastTriggerMs = timestampMs;
        // Decrease daily budget by 1
        this.dailyTriggerBudget -= 1;
        // Decrease PartOfDay budget by 1
        const currPartofDay: PartOfDay = TimeUtils.getPartOfDay(new Date(timestampMs));
        const currIndex = partOfDayProperties[currPartofDay.basic][currPartofDay.detail].index;
        this.partOfDayTriggerBudget[currIndex]--;
        log.debug(`Updated Daily budget: ${this.dailyTriggerBudget}`);
        log.debug(`Updated PartOfDay budget: ${this.partOfDayTriggerBudget}`);
    }

    /** 
     * Reset all rate limiters 
     */
    public reset(): void {
        // reset recency of last trigger
        this.lastTriggerMs = -1;
        // reset daily trigger budget
        this.dailyTriggerBudget = SignalRateLimiterStatus.MAX_TRIGGERS_PER_DAY_LIMIT;
        // reset PartOfDay trigger budget based on whether its the weekday or weekend
        for (let i = 0; i < PartOfDayTimes.length; i++) {
            const { basic, detail } = PartOfDayTimes[i].pod;
            if (this.isWeekend()) {
                this.partOfDayTriggerBudget[i] = Math.round(partOfDayProperties[basic][detail].weight.weekend * SignalRateLimiterStatus.MAX_TRIGGERS_PER_DAY_LIMIT);
            } else {
                this.partOfDayTriggerBudget[i] = Math.round(partOfDayProperties[basic][detail].weight.weekday * SignalRateLimiterStatus.MAX_TRIGGERS_PER_DAY_LIMIT);
            }
        }

        // Remove budget from PartOfDays that have already occured today
        const currPartOfDay = TimeUtils.getPartOfDay(new Date());
        const currIndex: number = partOfDayProperties[currPartOfDay.basic][currPartOfDay.detail].index;
        for (let i = 0; i < currIndex; i++) {
            this.partOfDayTriggerBudget[i] = 0;
        }
        log.debug(`Reset Daily budget: ${this.dailyTriggerBudget}`);
        log.debug(`Reset PartOfDay budget: ${this.partOfDayTriggerBudget}`);
    }


    /** 
     * Creates a timeout to occur at the next PartOfDay 
     */
    public createNextPartOfDayTimeout(): void {
        // Get current date and time properties
        const currPartOfDay: PartOfDay = TimeUtils.getPartOfDay(new Date());
        const currIndex: number = partOfDayProperties[currPartOfDay.basic][currPartOfDay.detail].index;
        const nextIndex: number = currIndex + 1 === PartOfDayTimes.length ? 0 : currIndex + 1;
        const nextPartOfDay: PartOfDay = PartOfDayTimes[nextIndex].pod;
        const deltaMs = this.diffPartsOfDay(currPartOfDay, nextPartOfDay);
        this.timeoutCallback = () => this.updatePartOfDayLimiter(currPartOfDay, nextPartOfDay);
        // Super important: tells Be's Timerspy that we are allowed to persist across skill boundaries
        (<any>this.timeoutCallback).isGlobalTimer = true;
        this.timeoutHandle = this.parent.jibo.timer.setTimeout(this.timeoutCallback, deltaMs);
        log.debug(`Created a timeout in ${Math.round(TimeUtils.msToMinutes(deltaMs))} minutes for ${nextPartOfDay.detail} ${nextPartOfDay.basic}`);
    }

    /** 
     * Calculate max triggers allowed per PartOfDay based on MAX_TRIGGERS_PER_HOUR_RATE
     */
    private calcMaxTriggersPartOfDay() {
        for (let currIndex = 0; currIndex < PartOfDayTimes.length; currIndex++) {
            const nextIndex: number = currIndex + 1 === PartOfDayTimes.length ? 0 : currIndex + 1;
            const deltaMs = this.diffPartsOfDay(PartOfDayTimes[currIndex].pod, PartOfDayTimes[nextIndex].pod);
            const maxTriggers = Math.round(TimeUtils.msToHours(deltaMs) * SignalRateLimiterStatus.MAX_TRIGGERS_PER_HOUR_RATE);
            const { basic, detail } = PartOfDayTimes[currIndex].pod;
            partOfDayProperties[basic][detail].maxTriggers = maxTriggers;
            log.debug(`${detail} ${basic} has ${maxTriggers} max allowed triggers`);
        }
    }

    /** 
     * The time difference between two Parts of the Day in milliseconds.
     */
    private diffPartsOfDay(current: PartOfDay, future: PartOfDay): number {
        const currIndex: number = partOfDayProperties[current.basic][current.detail].index;
        const futureIndex: number = partOfDayProperties[future.basic][future.detail].index;

        // Set current Datetime
        const currDatetime: Date = new Date();
        currDatetime.setHours(PartOfDayTimes[currIndex].time.hour);
        currDatetime.setMinutes(PartOfDayTimes[currIndex].time.minute);

        // Set future Datetime
        let futureDatetime: Date = new Date();
        // Check if crossing the day boundary
        if (futureIndex < currIndex) {
            // Add one day
            futureDatetime.setDate(currDatetime.getDate() + 1);            
        } else {
            futureDatetime.setDate(currDatetime.getDate());
        }
        futureDatetime.setHours(PartOfDayTimes[futureIndex].time.hour);
        futureDatetime.setMinutes(PartOfDayTimes[futureIndex].time.minute);

        //Calculate difference between future and current date time in milliseconds and return
        return futureDatetime.getTime() - currDatetime.getTime();
    }

    /**
     * Called at the next part of the day based on timeouts
     * Resets the rate limiters if its midnight
     * Performs rollover if the last part of the day had a remaining budget
     */
    private updatePartOfDayLimiter(lastPartOfDay: PartOfDay, currPartOfDay: PartOfDay) {
        log.debug(`Received timeout. Transitioned from ${lastPartOfDay.detail} ${lastPartOfDay.basic} to ${currPartOfDay.detail} ${currPartOfDay.basic}.`);
        // If its midnight, then reset rate limiters
        if (currPartOfDay.basic === PartOfDayBasic.NIGHT && currPartOfDay.detail === PartOfDayDetail.MID) {
            log.debug("Its midnight. Resetting all trigger rate limiters for the new day.");
            this.reset();
        } else {
            // Check whether we had remaining triggers in the last part of the day
            const currIndex = partOfDayProperties[currPartOfDay.basic][currPartOfDay.detail].index;
            const lastIndex = partOfDayProperties[lastPartOfDay.basic][lastPartOfDay.detail].index;
            const remainingBudget: number = this.partOfDayTriggerBudget[lastIndex];
            if (remainingBudget > 0) {
                // Clear its budget and rollover it to the remaining parts of the day.
                this.partOfDayTriggerBudget[lastIndex] = 0;
                this.rolloverToRemainingPartsOfDay(remainingBudget, currIndex);
                log.debug(`Rollovered PartOfDay budget: ${this.partOfDayTriggerBudget}`);
            } else {
                log.debug("Zero budget to rollover");
            }
        }
        // Reset timeout variables and create a new timeout for the next part of the day.
        this.timeoutHandle = null;
        this.timeoutCallback = null;
        this.createNextPartOfDayTimeout();
    }

    /** 
     * Evaluates whether a minimum time of RECENT_TRIGGER_EXPIRY_MS has passed before ever attempting another proactive request 
     */
    private evaluateTriggerRecency(): boolean {
        const sinceLastTriggerMs = Date.now() - this.lastTriggerMs;
        if (sinceLastTriggerMs > SignalRateLimiterStatus.RECENT_TRIGGER_EXPIRY_MS) {
            log.debug(`Passed: Last trigger was not recent: ${sinceLastTriggerMs}ms is greater than ${SignalRateLimiterStatus.RECENT_TRIGGER_EXPIRY_MS}ms`);
            return true;
        } else {
            log.info(`Failed: Last trigger was too recent: ${sinceLastTriggerMs}ms is less than or equal to ${SignalRateLimiterStatus.RECENT_TRIGGER_EXPIRY_MS}ms`);
            return false;
        }
    }

    /** 
     * Evaluates whether we have used up our trigger budget for the current part of the day 
     */
    private evaluatePartOfDayLimit(): boolean {
        const currPartOfDay: PartOfDay = TimeUtils.getPartOfDay(new Date());
        const currIndex = partOfDayProperties[currPartOfDay.basic][currPartOfDay.detail].index;
        const remainingBudget: number = this.partOfDayTriggerBudget[currIndex];
        if (remainingBudget > 0) {
            log.debug(`Passed: ${currPartOfDay.detail} ${currPartOfDay.basic} still has ${remainingBudget} triggers remaining`);
            return true;
        } else {
            log.info(`Failed: ${currPartOfDay.detail} ${currPartOfDay.basic} has ${remainingBudget} triggers remaining`);
            return false;
        }
    }

    /** 
     * Evaluates whether we have used up our trigger budget for the day.
     */
    private evaluateDailyLimit(): boolean {
        if (this.dailyTriggerBudget > 0) {
            log.debug(`Passed: Today still has ${this.dailyTriggerBudget} triggers remaining`);
            return true;
        } else {
            log.info(`Failed: Total has ${this.dailyTriggerBudget} triggers remaining`);
            return false;
        }
    }

    /**
     * Rollover the triggers to the remaining parts of the day specified by the startIndex.
     */
    private rolloverToRemainingPartsOfDay(triggers: number, startIndex: number) {
        // Decrease the rollover amount by allowed ROLLOVER_PROPORTION
        const totalTriggers = Math.round(SignalRateLimiterStatus.ROLLOVER_PROPORTION * triggers);
        log.debug(`Distributing ${SignalRateLimiterStatus.ROLLOVER_PROPORTION*100}% of ${triggers} = ${totalTriggers} triggers to the remaining parts of day.`);
        // Fill rollover array with zeros
        let rollover: number[] = Array.apply(null, Array(PartOfDayTimes.length)).map(Number.prototype.valueOf,0);
        // Distribute as a normalized weighted distribution
        let distributed = 0;
        for (let i = startIndex; i < PartOfDayTimes.length; i++) {
            const { basic, detail } = PartOfDayTimes[i].pod;
            if (this.isWeekend()) {
                rollover[i] = partOfDayProperties[basic][detail].weight.weekend * totalTriggers;
            } else {
                rollover[i] = partOfDayProperties[basic][detail].weight.weekday * totalTriggers;
            }
            distributed += rollover[i];
        }
        if (distributed) {
            // Normalize
            rollover = rollover.map(function (x) { return Math.round(x * totalTriggers / distributed); });
            // Add rollover to budget and cap at PartOfDay's maximum allowed triggers
            this.partOfDayTriggerBudget = this.partOfDayTriggerBudget.map(function (originalBudget, idx) {
                const { basic, detail } = PartOfDayTimes[idx].pod;
                const capBudget = partOfDayProperties[basic][detail].maxTriggers;
                return Math.min(originalBudget + rollover[idx], capBudget);
            });
        }
    }

    private isWeekend(): boolean {
        const dayOfWeek = new Date().getDay();
        // 6 is Saturday, 0 is Sunday
        return (dayOfWeek === 6) || (dayOfWeek === 0);
    }

    /**
     * Configure the static parameters of this signal, should be done before instantiation
     * @param {any} configuration Configuration of signal 
     */
    public static Configure(configuration: any) {
        try {
            SignalRateLimiterStatus.MAX_TRIGGERS_PER_DAY_LIMIT = configuration.MAX_TRIGGERS_PER_DAY_LIMIT;
            SignalRateLimiterStatus.MAX_TRIGGERS_PER_HOUR_RATE = configuration.MAX_TRIGGERS_PER_HOUR_RATE;
            SignalRateLimiterStatus.ROLLOVER_PROPORTION = configuration.ROLLOVER_PROPORTION;
            SignalRateLimiterStatus.RECENT_TRIGGER_EXPIRY_MS = configuration.RECENT_TRIGGER_EXPIRY_MS;
        } catch (e) {
            log.error("Could not configure static variables based on configuration file: ", e);
        }
    }
}