// External
import { ActionRuntime } from '../../../common/ActionRuntime';
import { LPSEntity, PresenceRecord, IdentificationSource} from "jibo-common-types";
import { TimeUtils } from 'jibo-cai-utils';
import { Event } from 'jibo-typed-events';
// Internal
import { log as parentLog } from '../../log';
import { OpportunityDetector } from '../../OpportunityDetector';
import { FiringSignal } from '../FiringSignal';


export {}; // For Type definition purposes

const log = parentLog.createChild('SignalFacePersisted');

 /**
  * SignalFacePersisted
  * (Type): Firing
  * (Handles): VisibleFaceStarted and IDAcquired events
  * (Fire Condition): If we see a visible face with ID_X at time t and still see ID_X at t + 1
  * @private
  */
export class SignalFacePersisted extends FiringSignal {

    // Even though we have a visible face, we want to give faceID a chance to identify the person.
    // And on a successful faceID, we actually cancel this waiting timer.
    // FACE_ID_WAIT_TIME_MS variable sets how long we should wait for the faceID.
    public static FACE_ID_WAIT_TIME_MS = TimeUtils.secondsToMs(4.5);
    // Emitted an event for these persisting faces
    public facePersisted = new Event<string>("Face Persisted");
    // Stores the entity IDs seen at time t.  Clears at time t + 1
    private currEntityIDs: Set<string> = new Set<string>();
    // Reference to the timeout handler that is created to avoid multiple simultaneous timers.
    private timeoutHandle = null;
    private timeoutStartMs = null;

    /**
     * Constructor
     */
    public constructor(parent: ActionRuntime, name: string, detector: OpportunityDetector) {
        super(parent, name, detector);
        // Super important: tells Be's Timerspy that we are allowed to persist across skill boundaries
        (<any>this.handleEntityTimeoutBind).isGlobalTimer = true;
    }

    public init(): void {
        this.parent.jibo.lps.identity.events.idAcquired.on(this.handleIDAcquiredBind);
        this.parent.jibo.lps.identity.events.visibleFaceStarted.on(this.handleVisibleFaceStartedBind);
    }

    public dispose(): void {
        this.parent.jibo.lps.identity.events.idAcquired.removeListener(this.handleIDAcquiredBind);
        this.parent.jibo.lps.identity.events.visibleFaceStarted.removeListener(this.handleVisibleFaceStartedBind);
    }

    // Internal bind function
    private handleVisibleFaceStartedBind = () => this.handleVisibleFaceStarted();

    /**
     * Called whenever a new visible face is detected
     */
    private handleVisibleFaceStarted(): void {
        // Create a Timeout Handler for FACE_ID_WAIT_TIME into the future.
        // Check we don't already have one.
        if (this.timeoutHandle) {
            log.debug("Got visible face, but already have a timeoutHandle");
        } else {
            // Store currently available entity IDs
            this.parent.jibo.lps.identity.getVisibleFaces().forEach((entity) => {
                log.debug("Got visible face of entity ID " + entity.id);
                this.currEntityIDs.add(entity.id);
            });
            this.timeoutHandle = this.parent.jibo.timer.setTimeout(this.handleEntityTimeoutBind, SignalFacePersisted.FACE_ID_WAIT_TIME_MS);
            this.timeoutStartMs = Date.now();
        }
    }

    // Internal bind function
    private handleEntityTimeoutBind = () => this.handleEntityTimeout();

    /**
     * Called when the timeout set in handleVisibleFaceStarted expires
     */
    private handleEntityTimeout() {
        // Check if we still have one of the entity IDs we saw before
        let matchedEntityID: string = null;
        const visibleFaces = this.parent.jibo.lps.identity.getVisibleFaces();
        if (visibleFaces.size) {
            visibleFaces.forEach((entity: LPSEntity) => {
                if (this.currEntityIDs.has(entity.id)) {
                    log.debug("Persisting face timeout expired.  I found same ID " + entity.id);
                    matchedEntityID = entity.id;
                    return;
                } else {
                    log.debug("Persisting face timeout expired. I did not find ID " + entity.id);
                }
            });
        } else {
            log.debug("Persisting face timeout expired. I have zero IDs");
        }

        // Reset variables
        this.timeoutHandle = null;
        this.timeoutStartMs = null;
        this.currEntityIDs.clear();

        // Fire if we found the same entity ID as before.
        if (matchedEntityID) {
            // Check present persons if this entity ID has looper ID
            const presentPersons = this.parent.jibo.lps.identity.getPresentPersons();
            const personID = presentPersons.find(person => (person.entityId === matchedEntityID && person.id !== "UNKNOWN" && person.id !== "NOT_TRAINED"));
            const emitID = personID ? personID.id : null;
            log.info(`Persisting face entity ID ${matchedEntityID} has an identity of ${emitID}`);
            this.facePersisted.emit(emitID);
        }
    }

    // Internal bind function
    private handleIDAcquiredBind = (data) => this.handleIDAcquired(data);

    /**
     * Called whenever an ID is acquired
     */
    private handleIDAcquired(presence: PresenceRecord) : void {
        // Cancel the timer if the ID is based on face rather than voice
        if (this.timeoutHandle && presence.identificationSource === IdentificationSource.FACE) {
            const deltaMs = TimeUtils.msToSeconds(Date.now() - this.timeoutStartMs);
            log.debug(`FaceID finally occured after ${deltaMs} seconds. Clearing out persisting face timeout`);
            this.parent.jibo.timer.clearTimeout(this.timeoutHandle);
            this.timeoutHandle = null;
            this.timeoutStartMs = null;
        }
    }

    /**
     * Configure the static parameters of this signal, should be done before instantiation
     * @param {any} configuration Configuration of signal 
     */
    public static Configure(configuration: any) {
        try {
            SignalFacePersisted.FACE_ID_WAIT_TIME_MS = TimeUtils.secondsToMs(configuration.FACE_ID_WAIT_TIME_SECS);
        } catch (e) {
            log.error("Could not configure static variables based on configuration file: ", e);
        }
    }
}
