import {Action} from './Action';
import {State} from '../common/State';
import {Goal} from '../goal/Goal';
import {ActionRuntime} from '../common/ActionRuntime';
import {ActionPolicy} from "./policies/ActionPolicy";
import {BasicPolicy} from "./policies/BasicPolicy";
import {MotivationGoal} from "../goal/goals/MotivationGoal";
import {DriveName} from '../common/Types';
import * as _ from 'lodash/lodash.min';
import { log as parentLog } from './log';

const log = parentLog.createChild('System');

export {}; // For type definition purposes

/**
 * @private
 */
export class ActionSystem {

    private actions: Action[] = [];
    private policy: ActionPolicy = new BasicPolicy(this.parent);

    constructor(private parent: ActionRuntime) {
    }

    /**
     * Adds an action to the action system
     * @param action
     */
    public addAction(action: Action) {
        log.debug(`adding action`, action.name);
        this.actions.push(action);
    }

    /**
     * Chooses the actions to be taken in a state given a set of goals
     */
    public chooseAction(state: State, goal: Goal, eligibleActions?: Action[]): Action {
        // If this goal has a suggested action to take
        const suggestedActionProvider = goal.options.action;
        if (suggestedActionProvider) {
            const suggestedAction = suggestedActionProvider();
            if (suggestedAction.isEligible(state)) {
                return suggestedAction;
            }
        }

        // Otherwise we choose an action based on installed policy
        const action = this.policy.selectAction(goal, state);
        if (action) {
            log.debug(`returning action`, action.name);
            return action;
        }

        // Lastly we select from the eligible actions
        // TODO This has to be thought though better, what actions should be available here (SSW for example?)
        if (!eligibleActions) {
            eligibleActions = this.actions.filter(a => a.isEligible(state));
            log.debug(`eligible actions: `, eligibleActions.map(a => a.name));
        }
        if (eligibleActions.length < 1) {
            log.debug(`no eligible actions`); // debug level because this gets called in a loop
        }

        // motivation handling here, because we need eligibleActions
        if (goal instanceof MotivationGoal) {
            // choose the best action to address the motivational state
            // Really interesting motivation system design question, whcih I'm including here temporarily:
            // Siggi asks: "would we ever want to select a best action even if the highest score is 0?
            // what about if (bestScore > 0)"
            // my answer: "In the simple case of a single drive, I think the answer is no: we only
            // want to consider actions that have a satiating effect on the drive (meaning, score < 0).
            // However it is possible that an action has a satiating effect on one drive that is
            // canceled out by a motivating (that is, increasing the value of the drive) effect on
            // one or more other drives. That's a really interesting question of motivation system
            // design, which I'd like to think over."
            let bestScore = 0;
            let bestActions: Action[] = [];
            const dat = this.parent.motivations.drivesAboveThreshold();
            for (let a of eligibleActions) {
                // each action's score is it's impact on a drive multiplied by drive value, summed over all drives
                // but we only want to do an action that addresses a motivation over the threshold.
                let score = 0;
                dat.forEach((d) => {
                    score += a.getDriveEffect(DriveName[d.name]) * d.value;
                });
                // lower is better, we're trying to reduce drive values.
                if (score < bestScore) {
                    bestActions = [a];
                    bestScore = score;
                } else if (Math.abs(score-bestScore) < 0.01) { // epsilon for score equality
                    bestActions.push(a);
                }
            }
            if (bestScore < 0) {
                return _.sample(bestActions);
            }
        }

    }
}
