/* tslint:disable:member-ordering */

import { ActionRuntime } from '../../common/ActionRuntime';
import { GoalProvider } from '../GoalProvider';
import { GoalPriority } from '../GoalPriority';
import { GoalPriorityType } from '../../common/Types';
import { SkillNames } from '../../common/Utils';
import { SSWGoal } from '../goals/SSWGoal';
import { TimeUtils } from 'jibo-cai-utils';
import { CircadianState } from 'jibo-common-types';
import { PromiseUtils } from 'jibo-cai-utils';
import { log as parentLog } from './log';

// new plan:
// on VisibleFace, set a timer for X seconds
// if timer expires, check that we still have the face, trigger a (non-identified) proactive greeting
// listen for idAcquired. on idAcquired, cancel the Visible Face timer, if any, and immediately trigger a proactive greeting
// (obeying the same constraints as currently re HJ, Idle times)

export { }; // For Type definition purposes

const PROACTIVE_GREETINGS_MINIMUM_INTERVAL_MS = TimeUtils.secondsToMs(10); // cannot offer a proactive greeting more often than this

/**
 * @private
 */
export class ProactiveGreetingGoalProvider extends GoalProvider {

    private FACE_ID_WAIT_TIME = 5; // seconds. Member variable for testing
    private handleVisibleFaceBind = this.handleVisibleFace.bind(this);
    private handleHJHEardBind = this.handleHJHeard.bind(this);
    private handleIdAcquiredBind = this.handleIdAcquired.bind(this);
    private handleTimeoutBind = this.handleTimeout.bind(this);
    private lastHJHeard = -1;
    private timeoutHandle = null;
    private timeoutStart = -1; // keep track of how long the timer ran for easier analytics
    private lastProactiveOffered = -1;
    private disableProactiveTrigger = false;

    log = parentLog.createChild('ProactiveGreetingGoalProvider');

    constructor(parent: ActionRuntime) {
        super(parent, 'Pro-active Greetings goal provider');
        this.handleTimeoutBind.isGlobalTimer = true;
    }

    init() {
        this.parent.jibo.lps.identity.events.visibleFaceStarted.on(this.handleVisibleFaceBind);
        this.parent.jibo.jetstream.events.hjHeard.on(this.handleHJHEardBind);
        this.parent.jibo.lps.identity.events.idAcquired.on(this.handleIdAcquiredBind);
    }

    dispose() {
        this.parent.jibo.lps.identity.events.idAcquired.removeListener(this.handleIdAcquiredBind);
        this.parent.jibo.jetstream.events.hjHeard.removeListener(this.handleHJHEardBind);
        this.parent.jibo.lps.identity.events.visibleFaceStarted.removeListener(this.handleVisibleFaceBind);
    }

    setDisableProactiveTrigger (bool: boolean): void {
        this.disableProactiveTrigger = bool;
    }

    /**
     * Called whenever HJ is heard
     */
    private handleHJHeard() {
        const now = this.parent.dateProvider.getDate();
        this.lastHJHeard = now.getTime();
    }

    /**
     * Called whenever a face comes into view
     */
    private handleVisibleFace() {
        if (this.timeoutHandle) {
            this.log.info('got visible face, but already have a timeoutHandle');
        } else {
            this.log.info(`got visible face, setting ${this.FACE_ID_WAIT_TIME} sec timeout`);
            this.timeoutStart = Date.now();
            this.timeoutHandle = this.parent.jibo.timer.setTimeout(this.handleTimeoutBind, TimeUtils.secondsToMs(this.FACE_ID_WAIT_TIME));
        }
    }

    /**
     * Called whenever an ID is acquired.
     */
    private async handleIdAcquired() {
        const IDdPersons = this.parent.jibo.lps.identity.getPresentPersons().filter(person => (person.id && person.id !== "UNKNOWN" && person.id !== "NOT_TRAINED")); // get all the present IDs
        this.log.info(`ID acquired, cancelling timeout and evaluating to trigger greeting. IDs present: ${JSON.stringify(IDdPersons)}`);
        // cancel the Visible Face timer, if any
        if (this.timeoutHandle) {
            this.log.info(`'Visible Face Started' timer ran for ${Date.now() - this.timeoutStart}ms before ID was acquired.`);
            this.parent.jibo.timer.clearTimeout(this.timeoutHandle);
            this.timeoutHandle = null;
            this.timeoutStart = -1;
        }
        // immediately trigger a proactive greeting
        await this.triggerIfAllowed();
    }

    /**
     * called when the timeout set in handleVisibleFace expires
     * @private
     * @memberOf ProactiveGreetingGoalProvider
     */
    private async handleTimeout() {
        this.log.info('timeout expired');
        this.timeoutHandle = null;
        // check that we still have the face,
        if (this.parent.jibo.lps.identity.isAnyonePresent()) {
            this.log.info('person still present, evaluating to trigger greeting');
            // trigger a (non-identified) proactive greeting
            await this.triggerIfAllowed();
        } else {
            this.log.info('no one present, not triggering');
        }
    }

    /**
     * Check state conditions (time in idle, time since HJ) and trigger a proactive
     *
     * @private
     *
     * @memberOf ProactiveGreetingGoalProvider
     */
    private async triggerIfAllowed() {
        // Only leave the skill to do a verbal proactive greeting if the conditions are correct.
        const conditionMet = await this.triggerConditionsMet();
        if (conditionMet) {
            this.log.info('conditions met, triggering proactive greeting');
            this.lastProactiveOffered = this.parent.dateProvider.getDate().getTime();
            if (this.disableProactiveTrigger) {
                this.log.warn('proactive greeting triggers have been disabled from package options');
            } else {
                this.triggerProactiveGreeting();
            }
        } else {
            this.log.info('conditions not met, not triggering greeting');
        }
    }

    /**
     * Check whether the conditions are correct to do a proactive greeting.
     * We must be in the correct state, with enough time having passed while in idle, and since the last hey jibo.
     * The person must not have been greeted recently (UNKNOWN counts as its own person).
     */
    private async triggerConditionsMet() {
        const state = this.parent.createState();
        const now = this.parent.dateProvider.getDate();
        const nowMs = now.getTime();
        const msInSkill = nowMs - state.skillStartTime.getTime();
        const msSinceHJ = nowMs - this.lastHJHeard;
        const msSinceLastGreeting = nowMs - this.lastProactiveOffered;

        let verbalGreetingNeeded = false;
        try {
            verbalGreetingNeeded = await this.ungreetedPersonVisible();
        } catch (error) {
            this.log.error("Call to ungreetedPersonVisible failed: ", error);
        }

        return (state.skillName === SkillNames.IDLE &&
            TimeUtils.msToSeconds(msInSkill) > 60 &&
            TimeUtils.msToSeconds(msSinceHJ) > 60 &&
            msSinceLastGreeting > PROACTIVE_GREETINGS_MINIMUM_INTERVAL_MS &&
            (state.circadian === CircadianState.ALERT || state.circadian === CircadianState.RELAXED) &&
            verbalGreetingNeeded);
    }

    /**
     * Check whether anyone around the robot hasn't been greeted for awhile.
     */
    private async ungreetedPersonVisible() {
        let eventDesc: any = {
            skillName: "@be/greetings", // TODO: Can we get this in the action layer?
            verbal: true
        };
        const persons = this.parent.jibo.lps.identity.getVisiblePersons();
        if (persons.length === 0) {
            this.log.info("No faces in fov.");
            return false;
        }

        const idPerson = persons.find(person => (person.id && person.id !== "UNKNOWN" && person.id !== "NOT_TRAINED"));
        if (idPerson) {
            eventDesc.personIDs = [idPerson.id];
        }

        let timeSince = -1; // Don't trigger a proactive greeting unless this is set
        try {
            timeSince = await PromiseUtils.timeout<number>(this.parent.jibo.im.getTimeSinceLast(eventDesc, this.parent.jibo.im.compareQueryFields), 5000); // wait for five seconds to ensure that we only timeout if something is very wrong
        } catch (error) {
            this.log.warn("Could not get interaction memory result: ", error);
        }

        let socialDriveValue = this.parent.jibo.action.getMotivationalDriveValue(this.parent.jibo.action.types.DriveName.SOCIAL);
        let hours = 1 + (1.0-socialDriveValue) * 2;
        let threshold = TimeUtils.hoursToMs(hours);
        const needsGreeting = timeSince > threshold;

        /**
         * List out all of the IDs in the FOV, how many entities are unknown, and how many are not-trained.
         * Easier for platform to check stats
         */
        const numUnknown = persons.filter(person => (person.id && person.id === "UNKNOWN")).length;
        const numNotTrained = persons.filter(person => (person.id && person.id === "NOT_TRAINED")).length;
        const identified = persons.filter(person => (person.id && person.id !== "UNKNOWN" && person.id !== "NOT_TRAINED"));
        this.log.info(`Verbal proactive greeting needed: ${needsGreeting}. Visible users - ID'd:${JSON.stringify(identified)}, UNKNOWN:${numUnknown}, NOT_TRAINED:${numNotTrained}`);

        return needsGreeting;
    }

    /**
     * Performs the actual logic for what to do when creating a pro-active greeting
     * This is called at runtime under the right conditions, or in debug using a Tunable button
     */
    triggerProactiveGreeting() {
        // Skill options for Greetings to perform a proactive greeting
        const goal = new SSWGoal(this.parent, {
            skillName: SkillNames.GREETINGS,
            skillOptions: {
                nlu: {
                    skill: SkillNames.GREETINGS,
                    intent: 'proactiveGreeting'
                }
            },
            criteria: {
                currentSkill: SkillNames.IDLE
            }
        });
        goal.options.priority = GoalPriority.Proactive;
        goal.options.priorityType = GoalPriorityType.SINGLETON_KEEP_FIRST;

        this.provideGoal(goal);
    }
}
