import { log as parentLog } from '../../log';
import { InhibitingSignal } from '../InhibitingSignal';
import { AmbientStats, TimeUtils } from 'jibo-cai-utils';
import { InputEnergy } from 'jibo-common-types';


export {}; // for type definition purposes

const AUDIO_SIGNAL_RATE = 20; // input energy comes in at 20hz
const log = parentLog.createChild('SignalLoudEnvironmentStatus');

/**
 * SignalLoudEnvironmentStatus
 * (Type): Inhibiting
 * (Pass Condition): Audio intensity long and short term averages meet criteria
 * (Description): Jibo should not trigger proactivity if the environment is too noisy
 * @private
 */
export class SignalLoudEnvironmentStatus extends InhibitingSignal {
    public static BASELINE_CEILING_DB = -40.0;
    public static RECENT_CEILING_DB = -30.0;
    public static BASELINE_PERIOD_SECS = 60.0;
    public static RECENT_PERIOD_SECS = 10.0;
    public static MINIMUM_RECENT_MEAN_DB = -40;
    public static DIVERGENCE_SENSITIVITY = 1.4; // The recent-mean must be this many baseline-stdevs away from the baseline-mean to be considered diverging
    public static RECENTLY_INHIBITED_DURATION_MS = 7500;
    public static INHIBIT_ON_SPIKE = true;
    private recentInhibitionStartTimeMs: number = null;
    private audioIntensityStats = new AmbientStats("SignalLoudEnvironmentStats", {
        baselineSize: (SignalLoudEnvironmentStatus.BASELINE_PERIOD_SECS * AUDIO_SIGNAL_RATE), // seconds * hz
        recentSize: (SignalLoudEnvironmentStatus.RECENT_PERIOD_SECS * AUDIO_SIGNAL_RATE), // seconds * hz
        minimumRecentMean: SignalLoudEnvironmentStatus.MINIMUM_RECENT_MEAN_DB,
        divergenceSensitivity: SignalLoudEnvironmentStatus.DIVERGENCE_SENSITIVITY, 
        }, log);

    private inputEnergyHandlerBind = (inputEnergy) => this.inputEnergyHandler(inputEnergy);
    private inputEnergyHandler(inputEnergy: InputEnergy) {
        this.audioIntensityStats.addSample(inputEnergy.db_rms);

        if (this.audioIntensityStats.buffersFilled() && this.audioIntensityStats.hasDeviatedFromBaseline()) {
            this.recentInhibitionStartTimeMs = Date.now();
        }
    }

    public init(): void { 
        // start listening to events
        this.parent.jibo.system.events.inputEnergy.on(this.inputEnergyHandlerBind);
    }
    
    public dispose(): void {
        // stop listening to events
        this.parent.jibo.system.events.inputEnergy.off(this.inputEnergyHandlerBind);
    }

    /**
     * Evaluates whether recent audio activity indicates an ongoing spike in loudness
     */
    private evaluateRelativeLoudness(): boolean {
        if (!SignalLoudEnvironmentStatus.INHIBIT_ON_SPIKE) {
            // Auto-pass if we're configured not to care about spikes.
            return true;
        }

        let isRecentlyInhibited = false;
        let sinceInhibitionStartMs = -1; 
        if (this.recentInhibitionStartTimeMs) {
            sinceInhibitionStartMs = Date.now() - this.recentInhibitionStartTimeMs;
            if (sinceInhibitionStartMs < SignalLoudEnvironmentStatus.RECENTLY_INHIBITED_DURATION_MS) {
                isRecentlyInhibited = true;
            } else {
                this.recentInhibitionStartTimeMs = null;
            }
        }

        // This should remain commented out. Necessary for proactivity tuning
        // this.audioIntensityStats.hasDeviatedFromBaseline() && log.info(`Failed: Relative noise is currently deviated from baseline and is too loud (based on relative thresholds). BaselineAudioEnergy:${this.audioIntensityStats.getBaselineMean()} RecentAudioEnergy:${this.audioIntensityStats.getRecentMean()}`);

        if (isRecentlyInhibited) {
            log.info(`Failed: Relative noise spike was loud ${sinceInhibitionStartMs}ms ago (based on relative thresholds). BaselineAudioEnergy:${this.audioIntensityStats.getBaselineMean().toFixed(2)} RecentAudioEnergy:${this.audioIntensityStats.getRecentMean().toFixed(2)}. In skill ${this.parent.currentSkillName}.`);
            return false;
        } else {
            log.debug(`Passed: Relative noise spike is NOT too loud (based on relative thresholds). BaselineAudioEnergy:${this.audioIntensityStats.getBaselineMean().toFixed(2)} RecentAudioEnergy:${this.audioIntensityStats.getRecentMean().toFixed(2)}. In skill ${this.parent.currentSkillName}.`);
            return true;
        }
    }
    
    /**
     * Evaluates whether baseline audio activity is above our absolute thresholds
     */
    private evaluateAbsoluteLoudness(): boolean {
        const baselineBelowThreshold = (this.audioIntensityStats.getBaselineMean() <= SignalLoudEnvironmentStatus.BASELINE_CEILING_DB);

        if (baselineBelowThreshold) {
            log.debug(`Passed: Environment baseline is NOT too loud (based on absolute thresholds). BaselineAudioEnergy:${this.audioIntensityStats.getBaselineMean().toFixed(2)} RecentAudioEnergy:${this.audioIntensityStats.getRecentMean().toFixed(2)}. In skill ${this.parent.currentSkillName}.`);
        } else {
            log.info(`Failed: Environment baseline is too loud (based on absolute thresholds). BaselineAudioEnergy:${this.audioIntensityStats.getBaselineMean().toFixed(2)} RecentAudioEnergy:${this.audioIntensityStats.getRecentMean().toFixed(2)}. In skill ${this.parent.currentSkillName}.`);
        }
        return baselineBelowThreshold;
    }

    /**
     * Evaluates whether the environment is loud or not
     * Pass: Moving average of audio-energy does NOT exceed the thresholds for both absolute and relative loudness
     * Fail: Moving average of audio-energy does exceed these thresholds
     */
    public evaluate(): boolean {
        // Don't evaluate until the buffers are filled / ready
        if (!this.audioIntensityStats.buffersFilled()) {
            log.debug(`Passed: Stats are not ready. Not inhibiting until buffers are full.`);
            return true;
        }

        const relativeLoudnessPass = this.evaluateRelativeLoudness();
        const absoluteLoudnessPass = this.evaluateAbsoluteLoudness();
        const pass = absoluteLoudnessPass && relativeLoudnessPass;

        return pass;
    }

    /**
     * Configure the static parameters of this signal, should be done before instantiation
     * @param {any} configuration Configuration of signal 
     */
    public static Configure(configuration: any) {
        try {
            SignalLoudEnvironmentStatus.BASELINE_CEILING_DB = configuration.BASELINE_CEILING_DB;
            SignalLoudEnvironmentStatus.RECENT_CEILING_DB = configuration.RECENT_CEILING_DB;
            SignalLoudEnvironmentStatus.BASELINE_PERIOD_SECS = configuration.BASELINE_PERIOD_SECS;
            SignalLoudEnvironmentStatus.RECENT_PERIOD_SECS = configuration.RECENT_PERIOD_SECS;
            SignalLoudEnvironmentStatus.MINIMUM_RECENT_MEAN_DB = configuration.MINIMUM_RECENT_MEAN_DB;
            SignalLoudEnvironmentStatus.DIVERGENCE_SENSITIVITY = configuration.DIVERGENCE_SENSITIVITY;
            SignalLoudEnvironmentStatus.RECENTLY_INHIBITED_DURATION_MS = TimeUtils.secondsToMs(configuration.RECENTLY_INHIBITED_DURATION_SECS);
            SignalLoudEnvironmentStatus.INHIBIT_ON_SPIKE = configuration.INHIBIT_ON_SPIKE;
        } catch (e) {
            log.error("Could not configure static variables based on configuration file: ", e);
        }
    }

    // This should remain commented out. necessary for proactivity tuning
    // public update() {
    //     this.evaluate();
    // }
}