import {Action} from '../Action';
import {ActionRuntime} from '../../common/ActionRuntime';
import {StateMachine} from 'jibo-state-machine';
import {ActionResult, Point3} from '../../common/Types';
import * as classes from './LookatClasses';
import {AttentionMode} from 'jibo-common-types';
import {expression} from 'jibo-expression-client';
import AcquireOptions = expression.AcquireOptions;

const AWAIT_FACE_TIMEOUT = 3; // NOTE: In seconds

const Flows = {
    React1: null,
    React2: null,
    React3: null,
    React4: null,
    React5: null,
};

export {}; // Needed for type definitions

/**
 * @private
 */
export class SearchAction extends Action {

    sm = new StateMachine();

    searchCandidates: AcquireOptions[] = [];

    // Unimplemented states
    isPersonVisible = new classes.PersonVisibleNearReferenceState(this.sm, this.parent, classes.AngleCalculatorType.XYZ);
    isLightingGood = new classes.LightingGoodState(this.sm, this.parent);

    // States
    attendToCandLoc = new classes.AttendToState(this.sm, this.parent, 'Attend to candidate location', false);
    attendToMotion = new classes.AttendToState(this.sm, this.parent, 'Attend to motion');
    reactNoCandidates = new classes.FlowState(this.sm, this.parent, 'React to no more search candidates', Flows.React4);
    pickNextSearchCandidate = new classes.PickNextLocationState(this);

    reactMotionDetected = new classes.FlowState(this.sm, this.parent, 'React to motion detected', Flows.React5);
    reactFaceFound = new classes.FlowState(this.sm, this.parent, 'React to face found', Flows.React3);
    reactFaceNotFound = new classes.FlowState(this.sm, this.parent, 'React to face not found', Flows.React2);
    awaitFace = new classes.AwaitFaceState(this, 'Await face', AWAIT_FACE_TIMEOUT); // Timeout in seconds

    reactBadLighting = new classes.FlowState(this.sm, this.parent, 'React to bad lighting', Flows.React1);
    attendToFace = new classes.AttendToState(this.sm, this.parent, 'Attend to face found');

    doneSucceeded = new classes.DoneState(this.sm, 'Done - Success', ActionResult.SUCCEEDED);
    doneFailed = new classes.DoneState(this.sm, 'Done - Failure', ActionResult.FAILED);


    constructor(parent: ActionRuntime, private initialRefPosition?: Point3) {
        super(parent, 'Search Action');

        // Here we connect the state machine
        this.sm.setInitial(this.isPersonVisible);

        // When a person is immediately found
        this.isPersonVisible.installTransitions(this.attendToFace, this.pickNextSearchCandidate);
        this.attendToFace.addDoneTransition(this.doneSucceeded);

        // When a person is not immediately found
        this.pickNextSearchCandidate.installTransitions(this.attendToCandLoc, this.reactNoCandidates);

        // When there are no more search candidates available
        this.reactNoCandidates.addDoneTransition(this.doneFailed);

        // When there are more search candidates available
        this.attendToCandLoc.addDoneTransition(this.isLightingGood);

        // When lighting is bad
        this.isLightingGood.installTransitions(this.awaitFace, this.reactBadLighting);
        this.reactBadLighting.addDoneTransition(this.pickNextSearchCandidate);

        // When lighting is good
        this.awaitFace.installTransitions(this.reactFaceFound, this.reactFaceNotFound, this.reactMotionDetected);

        // When motion is detected
        this.reactMotionDetected.addDoneTransition(this.attendToMotion);
        this.attendToMotion.addDoneTransition(this.doneSucceeded);

        // When person not found (timeout)
        this.reactFaceNotFound.addDoneTransition(this.pickNextSearchCandidate);

        // When person is found
        this.reactFaceFound.addDoneTransition(this.attendToFace);
    }

    /**
     * This method should be overridden by subclasses and provide
     * actual action run logic
     * @return {Promise<ActionResult>}
     */
    protected async runInternal(): Promise<ActionResult> {
        const pmHandler = await this.parent.jibo.expression.pushAttentionMode(AttentionMode.COMMAND);

        // We set initial reference position
        let refPosition = this.initialRefPosition;
        if (!refPosition) {
            // We calculate jibo's looking direction
            const features = this.parent.jibo.expression.features;
            refPosition = features.head.direction.clone().add(features.head.position);
        }
        this.isPersonVisible.setReferencePosition(refPosition);

        // TODO populate search candidates
        this.searchCandidates = [];

        // at Bard's request, removing alt hj location for the time being
        /*
        const now = this.parent.dateProvider.getDate().getTime();
        const hjDataMem = this.parent.memory.getHJData();

        if (hjDataMem && hjDataMem.data.alternate &&
            TimeUtils.msToSeconds(now - hjDataMem.time.getTime()) < 60) {

            this.searchCandidates.push({
                position: hjDataMem.data.alternate.position
            });
        }
        */

        const down = {x: refPosition.x, y: refPosition.y, z: 0.2};
        this.searchCandidates.push({position: down});
        this.searchCandidates.push({position: refPosition});

        // for development purposes
        /*
        this.searchCandidates.push({position: {x:-1.0, y:0.0, z:0.7}});
        this.searchCandidates.push({position: {x:0.0, y:1.0, z:0.7}});
        this.searchCandidates.push({position: {x:0.0, y:-1.0, z:0.7}});
        this.searchCandidates.push({position: {x:1.0, y:0.0, z:0.7}});
        */

        this.log.debug(`Searching locations: `, this.searchCandidates);

        try {
            const res = await this.sm.start();
            return res ? res : ActionResult.FAILED;
        } catch (e) {
            this.log.error('Search action state machine error: ', e);
            return ActionResult.FAILED;
        } finally {
            this.log.debug(`'${this.name}' SM trace: `, this.sm.traceToString());
            await pmHandler.release();
        }
    }

    protected async cancelInternal(): Promise<any> {
        this.log.info(`'${this.name}' canceled`);
        this.sm.stop();
    }
}
