import {ActionRuntime} from '../../common/ActionRuntime';
import {GoalProvider} from '../GoalProvider';
import {SnuggleGoal} from '../goals/SnuggleGoal';
import {SnuggleType} from "../../common/Types";
import {SkillNames} from "../../common/Utils";


export {}; // For Type definition purposes

/**
 * @private
 */
export class SnuggleGoalProvider extends GoalProvider {

    constructor(parent: ActionRuntime) {
        super(parent, 'Snuggle Goal Provider');
    }

    init() {
        this.parent.jibo.system.events.hatchOpen.on(this.hatchOpen);
        this.parent.jibo.system.events.hatchClose.on(this.hatchClose);
        this.parent.jibo.system.events.pluggedIn.on(this.pluggedIn);
        this.parent.jibo.system.events.unplugged.on(this.unplugged);
        this.parent.jibo.system.events.axisFaultOn.on(this.axisFault);
    }

    dispose() {
        this.parent.jibo.system.events.hatchOpen.removeListener(this.hatchOpen);
        this.parent.jibo.system.events.hatchClose.removeListener(this.hatchClose);
        this.parent.jibo.system.events.pluggedIn.removeListener(this.pluggedIn);
        this.parent.jibo.system.events.unplugged.removeListener(this.unplugged);
        this.parent.jibo.system.events.axisFaultOn.removeListener(this.axisFault);
    }

    hatchOpen = () => {
        this.performSnuggle(SnuggleType.HATCH_OPEN);
    }

    hatchClose = () => {
        this.performSnuggle(SnuggleType.HATCH_CLOSE);
    }

    pluggedIn = () => {
        this.performSnuggle(SnuggleType.PLUG);
    }

    unplugged = () => {
        this.performSnuggle(SnuggleType.UNPLUG);
    }

    axisFault = () => {
        this.performSnuggle(SnuggleType.AXIS_FAULT);
    }

    private performSnuggle(type: SnuggleType) {
        const state = this.parent.createState();
        // We only perform snuggles if we are not in tutorial or first contact
        if ((state.skillName !== SkillNames.TUTORIAL) &&
            (state.skillName !== SkillNames.FIRST_CONTACT)) {
            const goal = new SnuggleGoal(this.parent, type);
            this.provideGoal(goal);
        }
    }
}
