import {ActionRuntime} from '../../common/ActionRuntime';
import {Goal} from '../Goal';
import {State} from "../../common";
import {TimeUtils} from 'jibo-cai-utils';
import {GoalPriority} from "../GoalPriority";


export {}; // For Type definition purposes

/**
 * @private
 */
export class HJOnlyGoal extends Goal {

    constructor(parent: ActionRuntime) {
        super(parent, 'Hey Jibo Only', {
            priority: GoalPriority.HJOnly,
        });
    }

    /**
     * @param state
     * @override
     */
    canBeCulled(state: State): boolean {
        const seconds = TimeUtils.msToSeconds(
            this.parent.dateProvider.getDate().getTime() - this.created.getTime());

        return super.canBeCulled(state) || (seconds > 10);
    }
}
