import { log as parentLog } from '../../log';
import { InhibitingSignal } from '../InhibitingSignal';
import { AmbientStats, TimeUtils } from 'jibo-cai-utils';
import { types } from '@jibo/jetstream-client';
import { SkillNames } from '../../../common/Utils';
import { HJState } from './SignalHJStatus';


export {}; // for type definition purposes

const VAD_SIGNAL_RATE = 20; // VAD runs at 20 hz
const log = parentLog.createChild('SignalVADStatus');

/**
 * SignalVADStatus
 * (Type): Inhibiting
 * (Pass Condition): VAD long and short measurements meet criteria
 * (Description): Jibo should not trigger proactively if people are talking around him
 * TODO: if we want to increase the complexity of this signal, we might want to check the avg_frame_db corresponding to the
 * vadEvents to filter out quieter talking (people at a distance)
 * @private
 */
export class SignalVADStatus extends InhibitingSignal {

    // Slow and fast moving average periods
    public static BASELINE_PERIOD_SECS = 5.0;
    public static RECENT_PERIOD_SECS = 0.1;

    // Slow and fast moving average thresholds
    public static BASELINE_THRESHOLD = -0.3;
    public static RECENT_THRESHOLD = 0.35;
    public static RECENTLY_INHIBITED_DURATION_MS = 2000;
    private recentInhibitionStartTimeMs: number = null;

    private vadStats: AmbientStats = new AmbientStats("SignalVADStats", {
        baselineSize: (SignalVADStatus.BASELINE_PERIOD_SECS * VAD_SIGNAL_RATE), // seconds * hz
        recentSize: (SignalVADStatus.RECENT_PERIOD_SECS * VAD_SIGNAL_RATE), // seconds * hz
        }, log);

    private vadHandlerBind = (vadMessage) => this.vadHandler(vadMessage);
    /**
     * jetstream VAD events come with 2 - 3 VAD messages because jetsream operates at 20hz but VAD
     * operates at 50hz. We average the messages in an event and use that as our signal 
     */
    private vadHandler(vadMessage: types.VADEvent) {
        if (this.shouldSkipVADProcessing()) {
            // log.debug("Skipping vad message due to ongoing interaction.");
            // Don't parse VAD messages while Jibo is in an interaction
            // Clear out the stats buffer to prevent false inhibits once we begin processing VAD messages again
            this.vadStats.addSample(-1.0);
            return;
        }
        // log.debug("Got VAD Message.");

        let total = 0;
        vadMessage.VADevents.forEach(event => {
            total += event.vad;
        });
        total /= vadMessage.VADevents.length;
        this.vadStats.addSample(total);

        /**
         * If our recent mean is above the threshold inhibit for a period
         */
        if (this.vadStats.buffersFilled() && 
            (this.vadStats.getRecentMean() > SignalVADStatus.RECENT_THRESHOLD || this.vadStats.getBaselineMean() > SignalVADStatus.BASELINE_THRESHOLD)) {
            this.recentInhibitionStartTimeMs = Date.now();
        }
    }

    /**
     * Determine whether we should skip VAD signals
     * Skip if we're not in Idle (with exception to the surprise skill), we're handling an HJ, or embodied speech is finishing up a MIM.
     */
    private shouldSkipVADProcessing(): boolean {
        const skillState = this.parent.createState();
        return (skillState.skillName !== SkillNames.IDLE && skillState.skillName !== SkillNames.SURPRISES) ||
                (this.parent.proactive.signalHJStatus.getState() === HJState.IN_PROGRESS) ||
                (this.parent.jibo.embodied.speech.isActive());
    }

    public init(): void { 
        this.parent.jibo.jetstream.events.vad.on(this.vadHandlerBind);
    }

    public dispose(): void { 
        this.parent.jibo.jetstream.events.vad.off(this.vadHandlerBind);
     }

    /**
     * Evaluates VAD signal status
     * Pass: The long and short moving-average representations of the voice-activity-detector signal are BELOW threshold values, which means we have not yet crossed the threshold of detecting people talking
     * Fail: The long and short moving-average representations of the voice-activity-detector signal are ABOVE threshold values, which means we have crossed the boundary and detected people talking
     */
    public evaluate(skipLogging?: boolean): boolean {
        if (!this.vadStats.buffersFilled()) {
            if (!skipLogging) {
                log.info(`Passed: Stats are not ready. Not inhibiting until buffers are full.`);
            }
            return true;
        }

        // check whether we're currently in the period following a recent threshold failure
        let isRecentlyInhibited = false;
        let sinceInhibitionStartMs = -1; 
        if (this.recentInhibitionStartTimeMs) {
            sinceInhibitionStartMs = Date.now() - this.recentInhibitionStartTimeMs;
            if (sinceInhibitionStartMs < SignalVADStatus.RECENTLY_INHIBITED_DURATION_MS) {
                isRecentlyInhibited = true;
            } else {
                this.recentInhibitionStartTimeMs = null;
            }
        }

        const baseMean = this.vadStats.getBaselineMean().toFixed(2);
        const recentMean = this.vadStats.getRecentMean().toFixed(2);
        if (isRecentlyInhibited) {
            if (!skipLogging) {
                log.info(`Failed: Heard people talking ${sinceInhibitionStartMs}ms ago. baseline/recent: ${baseMean} / ${recentMean}. In skill ${this.parent.currentSkillName}.`);
            }
            return false;
        } else {
            if (!skipLogging) {
                log.debug(`Passed: Did not hear people talking. baseline/recent: ${baseMean} / ${recentMean}. No thresholds exceeded. In skill ${this.parent.currentSkillName}.`);
            }
            return true;
        }
    }

    public static Configure(configuration: any) {
        try {
            SignalVADStatus.BASELINE_PERIOD_SECS = configuration.BASELINE_PERIOD_SECS;
            SignalVADStatus.RECENT_PERIOD_SECS = configuration.RECENT_PERIOD_SECS;
            SignalVADStatus.BASELINE_THRESHOLD = configuration.BASELINE_THRESHOLD;
            SignalVADStatus.RECENT_THRESHOLD = configuration.RECENT_THRESHOLD;
            SignalVADStatus.RECENTLY_INHIBITED_DURATION_MS = TimeUtils.secondsToMs(configuration.RECENTLY_INHIBITED_DURATION_SECS);
        } catch (e) {
            log.error("Could not configure static variables based on configuration file: ", e);
        }
    }

    // This should remain commented out. necessary for proactivity tuning
    // public update() {
    //     this.evaluate();
    // }
}
