import {ActionRuntime} from '../common/ActionRuntime';
import {Goal} from './Goal';
import {Log} from 'jibo-log';
import {log as parentLog} from './log';


export { }; // For typings generation purpose

/**
 * @private
 */
export abstract class GoalProvider {

    parent: ActionRuntime;
    public log:Log;

    constructor(parent: ActionRuntime, public name: string) {
        this.parent = parent;
        this.log = parentLog.createChild(`GoalProvider.${name}`);
    }

    /**
     * Called on this provider when it should provide a goal
     * Puts goal in goal set and emits goalProvided event
     * @param {Goal} goal
     */
    public provideGoal(goal: Goal): void {
        goal.provider = this;
        this.parent.goals.addGoal(goal);
    }

    /**
     * Called when initializing
     */
    public abstract init(): void;

    /**
     * Called when destroying
     */
    public abstract dispose(): void;
}
