import {TimeUtils} from 'jibo-cai-utils';

import {ActionRuntime } from '../common/ActionRuntime';
import {State} from '../common/State';
import {ActionResult, ActionOptions, ActionStatus, DriveName} from '../common/Types';
import {Log} from 'jibo-log';
import {log as rootLog} from '../common/log';



const DEFAULT_ACTION_TIMEOUT = TimeUtils.secondsToMs(30);

/**
 * The core representation of an action in the action system. This class
 * is subclassed for various specific types of actions.
 * @class Action
 * @memberof jibo.action.action
 */
export class Action {

    static active: Action[] = [];

    /**
     * @internal
     */
    public parent: ActionRuntime;
    public log:Log;

    /**
     * Current status of the action
     * @name jibo.action.action.Action#status
     * @type jibo.action.types#ActionStatus
     * @readonly
     */
    public status = ActionStatus.NOT_RUNNING;

    private _runResolve: (result: ActionResult) => void;
    private _isCanceling: boolean;

    /**
     * Constructs an action object
     * @param {jibo.action.ActionRuntime} parent - The action runtime parent
     * @param {string} name - Name of action
     * @param {jibo.action.types.ActionOptions} options - Action options
     * the motivational drives.
     * Note that, due to a type-inferrance difficulty in TS, subclasses that specify driveEffects
     * will probably need to do so like this:
     * ```
     * class TestDriveAction extends Action {
     *    constructor() {
     *        super('TestDriveAction', new Map<DriveName, number>([<[DriveName, number]>[DriveName.TestDrive, -1.0]]));
     *    }
     * }
     * ```
     * Although not enforced here, due to bounds checking elsewhere, absolute value of drive effects
     * are effectively capped at 1.
     * @method jibo.action.action.Action#constructor
     * @private
     * @internal
     */
    constructor(parent: ActionRuntime, public name: string, public options: ActionOptions = {}) {
        this.parent = parent;
        // do we want error checking on driveEffects? I feel like we should,
        // but the DriveName enum keeps us from referencing drives that don't exist,
        // and I'm not sure I want to enforce bounds on drive effect sign or magnitude at this time.
        // (due to bounds checking elsewhere, absolute value of drive effects are effectively capped at 1.)
        this.options.driveEffects = this.options.driveEffects || new Map<DriveName, number>();
        this.options.timeoutMs = (this.options.timeoutMs === undefined) ?
            DEFAULT_ACTION_TIMEOUT :
            this.options.timeoutMs;
        this.log = rootLog.createChild(`Action.${name}`);
    }

    /**
     * Should be overridden by actions that want to respond to canceling
     * @private
     */
    protected async cancelInternal(): Promise<void> {
        return Promise.resolve();
    }

    /**
     * Cancels ongoing action (resolves promise with CANCELED status)
     * @private
     */
    public async cancel(): Promise<void> {
        this._cancel(ActionResult.CANCELED);
    }

    /**
     * How much this action will affect any given drive
     * @param {DriveName} drive - The name of the drive
     * @return {number}
     * @private
     */
    public getDriveEffect(drive: DriveName) {
        return this.options.driveEffects.get(drive) || 0;
    }

    /**
     * Runs this action
     * @return {Promise<ActionResult>}
     * @private
     */
    public async run(): Promise<ActionResult> {
        if (this.status === ActionStatus.RUNNING) {
            return Promise.reject<ActionResult>('Action already running');
        }

        this.log.debug(`Action status: ${this.status}`);
        this.status = ActionStatus.RUNNING;
        Action.active.push(this); // for debugging
        this.log.debug(`Active actions ${Action.active.length}: `, Action.active.map(a => a.name));


        // Set up action timeout
        let timeoutHandle: any;
        if (this.options.timeoutMs > 0) {
            const handler = () => this._cancel(ActionResult.TIMEOUT);
            (handler as any).isGlobalTimer = true; // Tells Be's Timerspy that we are allowed to persist across skill boundaries
            timeoutHandle = this.parent.jibo.timer.setTimeout(handler, this.options.timeoutMs);
        }

        const cleanup = () => {
            this.status = ActionStatus.NOT_RUNNING;
            this._runResolve = null;
            if (timeoutHandle) {
                timeoutHandle.destroy();
            }

            const ind = Action.active.indexOf(this); // for debugging
            if (ind >= 0) {
                Action.active.splice(ind, 1);
            }
        };

        return new Promise<ActionResult>((resolve, reject) => {
            this._runResolve = resolve;
            this.runInternal().then(result => {
                this.status = ActionStatus.NOT_RUNNING;
                this.log.debug('Completed with result: ', result);
                if (!this._isCanceling && this._runResolve) {
                    this._runResolve(result);
                }
            }).catch(e => reject(e));
        }).catch(e => {
            cleanup();
            this.log.error('Error running: ', e);
            throw e;
        }).then(result => {
            cleanup();
            return result;
        });
    }

    /**
     * This method should be overridden by subclasses and provide
     * actual action run logic
     * @return {Promise<ActionResult>}
     * @private
     */
    protected async runInternal(): Promise<ActionResult> {
        return Promise.resolve(ActionResult.SUCCEEDED);
    }

    /**
     * Determines if this action is eligible in a given state
     * Should be overridden by subclasses
     * @param {object} state
     * @return {boolean}
     * @private
     */
    public isEligible(state: State): boolean {
        return true;
    }

    private async _cancel(result: ActionResult) {
        if (!this._isCanceling && this._runResolve) {
            this._isCanceling = true;
            try {
                this.cancelInternal();
            } catch(e) {
                this.log.error('Error canceling: ', e);
            } finally {
                this.status = ActionStatus.NOT_RUNNING;
                this._isCanceling = false;
                if (this._runResolve) {
                    this._runResolve(result);
                }
            }
        }
    }
}
