// External (Only importing type definition)
import JiboImport = require('../../../jibo'); // NOTE: only for type declaration, not runtime dependency
import ProactiveRequestData = JiboImport.jetstream.types.ProactiveRequestData;
import ListenResult = JiboImport.jetstream.types.ListenResult;
import DelayedCall = JiboImport.utils.DelayedCall;
// Internal (Package)
import { ActionRuntime } from '../common/ActionRuntime';
import { SkillNames } from '../common/Utils';
import { GoalPriority } from '../goal/GoalPriority';
import { GoalProvider } from '../goal/GoalProvider';
import { SSWGoal } from '../goal/goals/SSWGoal';
// Internal (Proactive)
import { SignalHJStatus } from './signals/inhibitors/SignalHJStatus';
import { SignalJiboStatus } from './signals/inhibitors/SignalJiboStatus';
import { SignalSkillStatus } from './signals/inhibitors/SignalSkillStatus';
import { SignalNoMatchStatus } from './signals/inhibitors/SignalNoMatchStatus';
import { SignalRateLimiterStatus } from './signals/inhibitors/SignalRateLimiterStatus';
import { SignalIDAcquired } from './signals/firers/SignalIDAcquired';
import { SignalFacePersisted } from './signals/firers/SignalFacePersisted';
import { SignalSurprise } from './signals/firers/SignalSurprise';
import { SignalVADStatus } from './signals/inhibitors';
import { SignalLoudEnvironmentStatus } from './signals/inhibitors/SignalLoudEnvironmentStatus';
import { ArrivalTracker } from './signals/firers/arrival';
import { log as parentLog } from './log';
import { PODSignal } from './signals/PODSignal';
import * as SensorTypes from './signals/firers/arrival/SensorTypes';

const log = parentLog.createChild('OpportunityDetector');
interface LastResponse {
    timestamp: number;
    skillName: string;
}

export {}; // For typings generation purposes

/**
 * Firing signals can cause the proactive opportunity detector (POD) to evaluate.
 * On evaulation, the detector checks through all its inhibitor signals.
 * If we pass all, then we send out an official trigger to JetStream.
 * TODO: Remove being a GoalProvider
 * @private
 */
export class OpportunityDetector extends GoalProvider {

    // TODO: Heuristically evaluate a reasonable value
    public static MAX_JETSTREAM_RESPONSE_TIMEOUT_MS = 2500;
    public static MAX_SKILLSWITCH_RESPONSE_TIMEOUT_MS = 3000;
    // POD Signals of TYPE: Firing
    public signalIDAcquired: SignalIDAcquired = new SignalIDAcquired(this.parent, "ID Acquired Firing Signal", this);
    public signalFacePersisted: SignalFacePersisted = new SignalFacePersisted(this.parent, "Face Persisted Firing Signal", this);
    private signalSurprise: SignalSurprise = new SignalSurprise(this.parent, "Surprise Firing Signal", this);
    private arrivalTracker: ArrivalTracker = new ArrivalTracker(this.parent, "Arrival Tracker Firing Signal", this);
    // POD Signals of TYPE: Inhibiting
    private signalJiboStatus: SignalJiboStatus = new SignalJiboStatus(this.parent, "Jibo Status Inhibiting Signal");
    private signalSkillStatus: SignalSkillStatus = new SignalSkillStatus(this.parent, "Skill Status Inhibiting Signal");
    private signalNoMatchStatus: SignalNoMatchStatus = new SignalNoMatchStatus(this.parent, "No Match Status Inhibiting Signal");
    public signalHJStatus: SignalHJStatus = new SignalHJStatus(this.parent, "HJ Status Inhibiting Signal");
    public signalRateLimiterStatus: SignalRateLimiterStatus = new SignalRateLimiterStatus(this.parent, "Rate Limiter Status Inhibiting Signal");
    public signalVADStatus: SignalVADStatus = new SignalVADStatus(this.parent, "VAD Status Inhibiting Signal");
    public signalLoudEnvironmentStatus: SignalLoudEnvironmentStatus = new SignalLoudEnvironmentStatus(this.parent, "Audio Intensity Inhibiting Signal");
    // Timeout handle to report a warning if a response from jetstream exceeds MAX_JETSTREAM_RESPONSE_TIMEOUT
    private jetstreamTimeoutHandle: DelayedCall  = null;
    // Stores the last proactive response from jetstream
    private lastProactiveResponse: LastResponse = null;
    // Debug: Blocks or passes the sending of proactive triggers to jetstream
    private disableProactiveTrigger = false;
    // Collection of all firing and inhibiting signals
    private podSignals: PODSignal[] = [];

    /**
     * Constructor
     */
    public constructor(parent: ActionRuntime) {
        super(parent, 'Proactive Opportunity Detector trigger provider');
        this.parent = parent;
        // Super important: tells Be's Timerspy that we are allowed to persist across skill boundaries
        (<any>this.handleJetstreamTimeoutBind).isGlobalTimer = true;
        // Add all signals to array
        this.podSignals.push(this.signalJiboStatus);
        this.podSignals.push(this.signalSkillStatus);
        this.podSignals.push(this.signalHJStatus);
        this.podSignals.push(this.signalNoMatchStatus);
        this.podSignals.push(this.signalRateLimiterStatus);
        this.podSignals.push(this.signalVADStatus);
        this.podSignals.push(this.signalLoudEnvironmentStatus);
        this.podSignals.push(this.signalIDAcquired);
        this.podSignals.push(this.signalFacePersisted);
        this.podSignals.push(this.signalSurprise);
        this.podSignals.push(this.arrivalTracker);
    }

    /**
     * Init called by parent
     */
    public init(): void {
        // Init POD signals
        this.podSignals.forEach(ps => ps.init());
        // Used by POD itself
        this.parent.jibo.globalEvents.skillRelaunch.on(this.handleSkillRelaunchBind);
    }

    /**
     * Dispose called by parent
     */
    public dispose(): void {
        // Dispose POD signals
        this.podSignals.forEach(ps => ps.dispose());
        // Used by POD itself
        this.parent.jibo.globalEvents.skillRelaunch.removeListener(this.handleSkillRelaunchBind);
    }

    /**
     * Update called by parent at 10hz
     */
    public update(): void {
        this.arrivalTracker.update();

        // Signal update calls should remain commented out while the OpportunityDetector is being tuned and then deleted
        // this.signalVADStatus.update();
        // this.signalLoudEnvironmentStatus.update();
    }

    /**
     * Trigger a skill switch goal for Greeting
     */
    public triggerGreeting(): void {
        const goal = new SSWGoal(this.parent, {
            skillName: SkillNames.GREETINGS,
            skillOptions: {
                nlu: {
                    entities: {
                        skill: SkillNames.GREETINGS,
                    },
                    intent: 'proactiveGreeting'
                }
            },
            criteria: {
                currentSkill: SkillNames.IDLE
            }
        });
        goal.options.priority = GoalPriority.Proactive;

        this.provideGoal(goal);
    }

    public setDisableProactiveTrigger(disable: boolean): void {
        this.disableProactiveTrigger = disable;
    }

    /**
     * Evaluate first checks all the inhibitors.  If ALL passes, then send out official trigger.
     */
    public evaluate(proactiveRequest: ProactiveRequestData): void {
        log.info("Evaluating trigger source: " + proactiveRequest.triggerSource + " with looperID: ", proactiveRequest.triggerData.looperID);
        if (this.checkInhibitors()) {
            log.info("Passed all inhibitors");
            if (this.disableProactiveTrigger) {
                log.debug("Sending trigger messsages to Jetstream have been disabled from package options");
            } else {
                this.sendTrigger(proactiveRequest);
                this.signalRateLimiterStatus.addTriggerEvent();
            }
        } else {
            log.info("Failed an inhibitor");
        }
    }

    /**
     * Check that environmental signals are not inhibiting
     */
    public checkEnvironmentInhibitors(): boolean {
        return this.signalVADStatus.evaluate() &&
               this.signalLoudEnvironmentStatus.evaluate();
    }

    /**
     * Check that all inhibitors evaluate to true.
     */
    private checkInhibitors(): boolean {
        return this.signalHJStatus.evaluate() &&
            this.signalJiboStatus.evaluate() &&
            this.signalSkillStatus.evaluate() &&
            this.signalNoMatchStatus.evaluate() &&
            this.signalRateLimiterStatus.evaluate() &&
            this.checkEnvironmentInhibitors();
    }

    /**
     * Send the Trigger out to JetStream!
     */
    private async sendTrigger(proactiveRequest: ProactiveRequestData): Promise<void> {
        log.info("Sending proactive trigger to jetstream");
        // Create jetstream timeout handler
        this.jetstreamTimeoutHandle = this.parent.jibo.timer.setTimeout(
            this.handleJetstreamTimeoutBind, OpportunityDetector.MAX_JETSTREAM_RESPONSE_TIMEOUT_MS);
        try {
            const requestTimestamp = Date.now();
            // Send proactive request to jetstream.
            const proactiveSession = await this.parent.jibo.jetstream.triggerProactive(proactiveRequest);
            // Wait for promise to resolve when a response message has been received.
            const proactiveResponse = await proactiveSession.promise;
            // On successful response from jetstream, clear the timeout
            this.parent.jibo.timer.clearTimeout(this.jetstreamTimeoutHandle);
            this.jetstreamTimeoutHandle = null;
            // Store skill match if exists
            if (proactiveResponse.match) {
                this.lastProactiveResponse = {
                    skillName: proactiveResponse.match.skillID,
                    timestamp: requestTimestamp,
                };
                // If the trigger source was from an ID-ed ARRIVAL and we are about to launch a skill
                // with this ID info, then we need to update what the identity service thinks about the active speaker
                if (proactiveRequest.triggerData.looperID && proactiveRequest.triggerSource === this.parent.jibo.jetstream.types.ProactiveTriggerSource.NEW_ARRIVAL) {
                    log.info(`Updating identity service active speaker to ${proactiveRequest.triggerData.looperID}`);
                    this.parent.jibo.lps.identity.setActiveSpeaker({
                        speakers: [{
                            speaker: proactiveRequest.triggerData.looperID,
                            score: 100, // TODO: Put a value that actually means something here.
                            accepted: true,
                            high_confidence: true,
                        }],
                        snr: 1
                    }, 'JCP');
                }
            }
            // Print out response time
            const deltaTime = Date.now() - requestTimestamp;
            log.info(`Got a successful jetstream response in ${deltaTime} milliseconds`);
        } catch (err) {
            log.error(err.message);
        }
        // Temporarily for testing trigger Greeting Skill
        // this.triggerGreeting();
    }

    // Internal bind function
    private handleJetstreamTimeoutBind = () => this.handleJetstreamTimeout();

    /**
     * This timeout will occur if not cancelled by a successful jetstream response.
     * A warning is printed if a jetstream response was not received within MAX_JETSTREAM_RESPONSE_TIMEOUT
     */
    private handleJetstreamTimeout(): void {
        log.warn(`A proactive trigger was sent but did not receive a response from jetstream within ${OpportunityDetector.MAX_JETSTREAM_RESPONSE_TIMEOUT_MS} milliseconds`);
    }

    // Internal bind function
    private handleSkillRelaunchBind = (data) => this.handleSkillRelaunch(data);

    /**
     * We want a robot to immediately/contingently respond with a skill once a proactive moment is detected.
     * If the robot takes too long, then the proactive moment can pass.
     * To track for this, a warning is printed if a skill relaunch caused by a proactive request exceeds MAX_SKILLSWITCH_RESPONSE_TIMEOUT.
     * Note: There is about ~100ms between the skill relaunch command to the actual skill behavior being exhibited on Jibo.
     * But this is small compared to the time it takes for a hub/cloud response.
     */
    private handleSkillRelaunch(data: ListenResult): void {
        if (this.lastProactiveResponse) {
            const skillName = data.match && data.match.skillID;
            const isProactive = data.match && data.match.isProactive;
            if (isProactive && this.lastProactiveResponse.skillName === skillName) {
                const deltaTime = Date.now() - this.lastProactiveResponse.timestamp;
                if (deltaTime < OpportunityDetector.MAX_SKILLSWITCH_RESPONSE_TIMEOUT_MS) {
                    log.info(`Got a successful skill switch response to ${skillName} in ${deltaTime} milliseconds`);
                } else {
                    log.warn(`Got a slow skill switch response to ${skillName} in ${deltaTime} milliseconds which exceeds our max response time of ${OpportunityDetector.MAX_SKILLSWITCH_RESPONSE_TIMEOUT_MS} milliseconds`);
                }
                this.lastProactiveResponse = null;
            }
        }
    }

    /**
     * Reset arrival tracker state machine to go to state: Nobody
     */
    public resetArrivalTrackerSM(): void{
        this.arrivalTracker.emitResetEvent();
    }

    /**
     * Configure the static parameters of the opportunity detector, should be done before instantiation
     * @param {any} configuration Configuration of the opportunity detector
     */
    public static Configure(configuration: any) {
        try {
            OpportunityDetector.MAX_JETSTREAM_RESPONSE_TIMEOUT_MS = configuration.MAX_JETSTREAM_RESPONSE_TIMEOUT_MS;
            OpportunityDetector.MAX_SKILLSWITCH_RESPONSE_TIMEOUT_MS = configuration.MAX_SKILLSWITCH_RESPONSE_TIMEOUT_MS;
        } catch (e) {
            log.error("Could not configure static variables based on configuration file: ", e);
        }
    }
}

// Read package.json file and grab proactive options
const findRoot = require('find-root');
const ROOT_PATH = findRoot(__dirname);
try {
    const configFile = fs.readFileSync(path.join(ROOT_PATH, 'config/ProactiveConfiguration.json'), 'utf8');
    const configJSON = JSON.parse(configFile);

    // Opportunity Detector
    OpportunityDetector.Configure(configJSON.OpportunityDetector);
    // Arrival Tracker
    ArrivalTracker.Configure(configJSON.ArrivalTracker);

    // Sensor Types
    Object.assign(SensorTypes.faceIDAcquiredSensor, configJSON.SensorTypes.faceIDAcquiredSensor);
    Object.assign(SensorTypes.facePersistedSensor, configJSON.SensorTypes.facePersistedSensor);
    Object.assign(SensorTypes.hjHeardSensor, configJSON.SensorTypes.hjHeardSensor);
    Object.assign(SensorTypes.headTouchedSensor, configJSON.SensorTypes.headTouchedSensor);
    Object.assign(SensorTypes.motionEntitySensor, configJSON.SensorTypes.motionEntitySensor);
    Object.assign(SensorTypes.localizedSoundSensor, configJSON.SensorTypes.localizedSoundSensor);
    Object.assign(SensorTypes.loudSoundSpikeSensor, configJSON.SensorTypes.loudSoundSpikeSensor);
    Object.assign(SensorTypes.screenTouchedSensor, configJSON.SensorTypes.screenTouchedSensor);
    Object.assign(SensorTypes.heardVoicesSensor, configJSON.SensorTypes.heardVoicesSensor);
    Object.assign(SensorTypes.visibleFaceSensor, configJSON.SensorTypes.visibleFaceSensor);

    // Signals
    SignalFacePersisted.Configure(configJSON.Signals.SignalFacePersisted);
    SignalHJStatus.Configure(configJSON.Signals.SignalHJStatus);
    SignalLoudEnvironmentStatus.Configure(configJSON.Signals.SignalLoudEnvironmentStatus);
    SignalNoMatchStatus.Configure(configJSON.Signals.SignalNoMatchStatus);
    SignalRateLimiterStatus.Configure(configJSON.Signals.SignalRateLimiterStatus);
    SignalVADStatus.Configure(configJSON.Signals.SignalVADStatus);
} catch (error) {
    console.error("Error loading ProactiveConfiguration.json in jibo-action-system for proactive configuration", error);
}
