// External
import { Event } from 'jibo-typed-events';
import { StateMachine, State } from 'jibo-state-machine';
import { TimeUtils } from 'jibo-cai-utils';
// Only importing type definition
import JiboImport = require('../../../../../../jibo'); // NOTE: only for type declaration, not runtime dependency
import NewArrivalRequestData = JiboImport.jetstream.types.NewArrivalRequestData;
// Internal
import { log as parentLog } from '../../../log';
import { FiringSignal } from '../../FiringSignal';
import * as SensorTypes from './SensorTypes';
import Sensor = SensorTypes.Sensor;


const log = parentLog.createChild('ArrivalTracker');

export {}; // For Type definition purposes

/**
 * @private
 */
export class ArrivalTracker extends FiringSignal {
    public static SM_UPDATE_PERIOD_MS = 1000; // Update rate of state machine
    public static SM_LOG_PERIOD_MS = 10000; // Logging rate of state machine
    public static POSSIBLEBODY_TO_NOBODY_INTERNAL_TRANSITION_TIMEOUT_MINS = 3;

    // Statemachine
    private sm: StateMachine;

    // States
    private nobody: State<string>;
    private somebody: State<Sensor>;
    private possiblebody: State<Sensor>;

    // Events
    private hardEvidenceEvent: Event<Sensor>;
    private modEvidenceEvent: Event<Sensor>;
    private softEvidenceEvent: Event<Sensor>;
    private resetEvent: Event<string>;

    private timer = null;
    private timerExpiryMs = -1;

    private lastStateMachineTick = 0;
    private lastPrintoutTick = 0;

    private recentSoundDetected = false;
    private recentMotionDetected = false;
    private recentFaceDetected = false;
    private recentVoicesHeard = false;

    /**
     * Init
     */
    public init(): void {
        this.detector.signalIDAcquired.faceIDAcquired.on(this.faceIDAcquiredListener);
        this.detector.signalFacePersisted.facePersisted.on(this.facePersistedListener);
        this.parent.jibo.jetstream.events.hjHeard.on(this.hjHeardListener);
        this.parent.jibo.system.events.touchOn.on(this.headTouchListener);
        this.parent.jibo.globalEvents.shared.screenGesture.on(this.screenTouchListener);
        this.parent.jibo.lps.detector.ambientAudioSpike.trigger.on(this.ambientAudioSpikeListener);
        this.createAndStartStateMachine();
    }

    /**
     * Dispose
     */
    public dispose(): void {
        this.detector.signalIDAcquired.faceIDAcquired.removeListener(this.faceIDAcquiredListener);
        this.detector.signalFacePersisted.facePersisted.removeListener(this.facePersistedListener);
        this.parent.jibo.jetstream.events.hjHeard.removeListener(this.hjHeardListener);
        this.parent.jibo.system.events.touchOn.removeListener(this.headTouchListener);
        this.parent.jibo.globalEvents.shared.screenGesture.removeListener(this.screenTouchListener);
        this.parent.jibo.lps.detector.ambientAudioSpike.trigger.removeListener(this.ambientAudioSpikeListener);
        this.sm.stop();
    }

    /**
     * Updates at 10hz
     */
    public update(): void {
        const deltaSM = Date.now() - this.lastStateMachineTick;
        const deltaPrintout = Date.now() - this.lastPrintoutTick;

        // Update streaming perception data at 10hz
        // We are storing some memory here.  Before the state machine gets a chance to update, did we get a recent motion, face, or sound detected?
        // If so, store the true boolean value in variable; it will be reset to false by the state machine once processed.
        const audibleEntity = this.parent.jibo.lps.getClosestAudibleEntity();
        if (audibleEntity && audibleEntity.confidence >= SensorTypes.localizedSoundSensor.threshold) {
            this.recentSoundDetected = true;
            // Leave uncommented as high frequency logging but exact string needed for tuning regex
            // log.debug(`Registered localized sound: ${audibleEntity.confidence.toFixed(2)}`);
        }

        // TODO: Any motion vs closest visual entity is a motion?
        const closestVisualEntity = this.parent.jibo.lps.getClosestVisualEntity(); 
        if (closestVisualEntity && closestVisualEntity.description && closestVisualEntity.description === 'motion') {
            this.recentMotionDetected = true;
            // Leave uncommented as high frequency logging but exact string needed for tuning regex
            // log.debug('Registered a motion entity');
        }

        if (this.parent.jibo.lps.identity.getVisibleFaces().size > 0) {
            this.recentFaceDetected = true;
            // Leave uncommented as high frequency logging but exact string needed for tuning regex
            // log.debug('Registered a visible face');
        }

        if(!this.detector.signalVADStatus.evaluate(true)){
            this.recentVoicesHeard = true;
            // Leave uncommented as high frequency logging but exact string needed for tuning regex
            // log.debug('Registered a heard voice');
        }

        // Update state machine
        if (deltaSM >= ArrivalTracker.SM_UPDATE_PERIOD_MS) {
            // If in Somebody state, check for hard evidence to emit.
            if (this.sm.getCurrentState() === this.somebody) {
                // If a visible face exists, then emit moderate evidence
                if (this.recentFaceDetected) {
                    this.modEvidenceEvent.emit(SensorTypes.visibleFaceSensor);
                }
                // If heard voices, then emit moderate evidence
                if (this.recentVoicesHeard){
                    this.modEvidenceEvent.emit(SensorTypes.heardVoicesSensor);
                }
            }
            // If in Possiblebody state, check for soft evidence to emit.
            else if (this.sm.getCurrentState() === this.possiblebody) {
                // If a motion entity exists, then emit soft evidence
                if (this.recentMotionDetected) {
                    this.softEvidenceEvent.emit(SensorTypes.motionEntitySensor);
                }
                // If an audible entity exists and localization confidence is above threshold, then emit soft evidence
                if (this.recentSoundDetected) {
                    this.softEvidenceEvent.emit(SensorTypes.localizedSoundSensor);
                }
            }
            // Reset
            this.recentFaceDetected = false;
            this.recentMotionDetected = false;
            this.recentSoundDetected = false;
            this.recentVoicesHeard = false;
            this.lastStateMachineTick = Date.now();
        }

        // Print state machine information periodically and if not in state Nobody
        if (this.sm.getCurrentState() !== this.nobody && deltaPrintout >= ArrivalTracker.SM_LOG_PERIOD_MS) {
            const deltaTime = TimeUtils.msToMinutes(this.timerExpiryMs - Date.now());
            log.debug(`[${this.sm.getCurrentState().name}] ticktock: ${deltaTime.toFixed(2)} minutes`);
            this.lastPrintoutTick = Date.now();
        }
    }

    /**
     * Emit reset to state machine
     */
    public emitResetEvent(){
        this.resetEvent.emit();
    }

    /**
     * Emit soft evidence to state machine
     */
    private emitSoftEvidence(data: any, sensor: Sensor) {
        this.softEvidenceEvent.emit(sensor);
    }

    /**
     * Emit moderate evidence to state machine
     */
    private emitModerateEvidence(data: any, sensor: Sensor) {
        this.modEvidenceEvent.emit(sensor);
    }

    /**
     * Emit hard evidence to state machine
     */
    private emitHardEvidence(entityID: string, sensor: Sensor) {
        this.hardEvidenceEvent.emit(sensor);
    }

    /**
     * Arrival Tracker's Listeners
     */
    private faceIDAcquiredListener = (entityID) => {
        const sensor: Sensor = {
            ...SensorTypes.faceIDAcquiredSensor,
            looperID: entityID,
        };
        log.debug('Registered face ID acquired');
        this.emitHardEvidence(entityID, sensor);
    }

    private facePersistedListener = (entityID) => {
        const sensor: Sensor = {
            ...SensorTypes.facePersistedSensor,
            looperID: entityID,
        };
        log.debug('Registered face persisted');
        this.emitHardEvidence(entityID, sensor);
    }

    private hjHeardListener = (data) => {
        log.debug('Registered HJ heard');
        this.emitHardEvidence(data, SensorTypes.hjHeardSensor);
    }

    private headTouchListener = (data) => {
        log.debug('Registered head touch');
        this.emitModerateEvidence(data, SensorTypes.headTouchedSensor);
    }

    private screenTouchListener = (data) => {
        log.debug('Registered screen touch');
        this.emitModerateEvidence(data, SensorTypes.screenTouchedSensor);
    }

    private ambientAudioSpikeListener = (data) => {
        log.debug('Registered loud spike sound');
        this.emitSoftEvidence(data, SensorTypes.loudSoundSpikeSensor);
    }

    /**
     * Creates the arrival tracker's state machine and starts it.  Has smart error-checking to later re-attempt.
     */
    private createAndStartStateMachine(): Promise<void> {
        this.createStateMachine();
        return this.sm.start()
            .catch(error => {
                log.error(`Error in Arrival Tracker state machine on start:`, error);
                log.info(`Waiting to restart state machine...`);
                return TimeUtils.wait(1000);
            }).then(() => {
                log.info(`Restarting Arrival Tracker SM`);
                return this.createAndStartStateMachine();
            });
    }

    private createStateMachine(): void {
        this.sm = new StateMachine();

        this.nobody = new State<string>(this.sm, 'Nobody');
        this.somebody = new State<Sensor>(this.sm, 'Somebody');
        this.possiblebody= new State<Sensor>(this.sm, 'Possiblebody');

        // Events are transitions for a state machine
        // Hard evidence events are capture by sensors specific to detecting people with high accuracy and indicative of a person arriving.
        // Moderate evidence events are captured by sensors specific to detecting people but likely to have false positives or not specific to an arrival.
        // Soft evidence events are captured by sensors that could not differentiate between a cat vs person.
        this.hardEvidenceEvent = new Event<Sensor>('Hard Evidence Event');
        this.modEvidenceEvent = new Event<Sensor>('Moderate Evidence Event');
        this.softEvidenceEvent = new Event<Sensor>('Soft Evidence Event');
        this.resetEvent = new Event<string>('Reset Event');

        // Transition: Nobody => Somebody (Cause: Hard evidence event)
        this.nobody.addTypedEventTransition(this.hardEvidenceEvent, this.somebody);

        // Transition: Somebody => Somebody (Cause: Hard or moderate evidence events)
        this.somebody.addTypedEventTransition(this.hardEvidenceEvent, this.somebody);
        this.somebody.addTypedEventTransition(this.modEvidenceEvent, this.somebody);
        // Transition: Somebody => Possiblebody (Cause: Internal timeout)
        this.somebody.addInternalTransition('Internal Timeout', this.possiblebody);
        // Transition: Somebody => Nobody (Cause: Reset)
        this.somebody.addTypedEventTransition(this.resetEvent, this.nobody);

        // Transition: Possiblebody => Somebody (Cause: Hard or moderate evidence event)
        this.possiblebody.addTypedEventTransition(this.hardEvidenceEvent, this.somebody);
        this.possiblebody.addTypedEventTransition(this.modEvidenceEvent, this.somebody);
        // Transition: Possiblebody => Possiblebody (Cause: Soft evidence event)
        this.possiblebody.addTypedEventTransition(this.softEvidenceEvent, this.possiblebody);
        // Transition: Possiblebody => Nobody (Cause: Internal timeout)
        this.possiblebody.addInternalTransition('Internal Timeout', this.nobody);
        // Transition: Possiblebody => Nobody (Cause: Reset)
        this.possiblebody.addTypedEventTransition(this.resetEvent, this.nobody);

        // State Definition: Nobody - Nobody is around.  Only hard evidence can transition to Sombody state.
        this.nobody.onEntry = (transition, result) => log.debug(`[${this.nobody.name}] Entered`);

        // State Definition: Somebody - Somebody is around since got either a hard or moderate evidence event from a sensor.
        this.somebody.onEntry = (transition, sensor: Sensor) => {
            // If coming from Nobody state and not from an HJ, then send new arrival proactive trigger
            if (transition.getSourceState() === this.nobody && sensor.name !== SensorTypes.hjHeardSensor.name) {
                log.debug(`[${this.somebody.name}] Entered from Nobody state; Sending new arrival proactive trigger.`);
                const arrivalRequest: NewArrivalRequestData = {
                    triggerSource: this.parent.jibo.jetstream.types.ProactiveTriggerSource.NEW_ARRIVAL,
                    triggerData: {
                        looperID: sensor.looperID,
                    }
                };
                this.detector.evaluate(arrivalRequest);
            }
            log.debug(`[${this.somebody.name}] Entered with timeout of ${sensor.timeoutMins} minutes from ${transition} Sensor: ${sensor.name}`);
            this.createNewTimerTransition(sensor.timeoutMins, this.somebody, this.possiblebody);
        };
        this.somebody.onExit = (transition) => {
            // Clear timer if transitioning to another state and not looping back to the same state. 
            if (transition.getSourceState() !== this.somebody) {
                this.clearTimer();
            }
        };

        // State Definition: Possiblebody - It is possible that somebody is around (low confidence state).  Soft evidence events allows the continuation of this state.
        this.possiblebody.onEntry = (transition, sensor: Sensor) => {
            // Choose default timeout if we entered this state without a sensor specified (e.g. because of a timeout transition)
            const timeout = sensor ? sensor.timeoutMins : ArrivalTracker.POSSIBLEBODY_TO_NOBODY_INTERNAL_TRANSITION_TIMEOUT_MINS;
            const sensorInfo = sensor ? `Sensor: ${sensor.name}` : '';
            log.debug(`[${this.possiblebody.name}] Entered with timeout of ${timeout} minutes from ${transition} ${sensorInfo}`);
            this.createNewTimerTransition(timeout, this.possiblebody, this.nobody);
        };
        this.possiblebody.onExit = (transition) => {
            // Clear timer if transitioning to another state and not looping back to the same state. 
            if (transition.getSourceState() !== this.possiblebody) {
                this.clearTimer();
            }
        };

        // Initialize first state
        this.sm.setInitial(this.nobody);
    }

    private clearTimer(): void{
        if (this.timer) {
            clearTimeout(this.timer);
            this.timer = null;
        }
        this.timerExpiryMs = -1;
    }

    private createNewTimerTransition(newTimeoutMinutes: number, from: State, next: State): void {
        // Convert from minutes to milliseconds
        const newTimeoutMs = TimeUtils.minutesToMs(newTimeoutMinutes);
        // Check if newTimeout will extend the current one
        if (this.timerExpiryMs > newTimeoutMs + Date.now()) {
            return;
        }
        // Clear current timer and set new timer based with new timeout
        this.clearTimer();
        this.timerExpiryMs = newTimeoutMs + Date.now();
        this.timer = setTimeout(() => {
            this.clearTimer();
            // Sanity check that when the timer goes off the current state is still the original 'from' state
            if (this.sm.getCurrentState() === from) {
                // Make the transition
                from.transitionTo(next);
            } else {
                log.warn(`This should not have happened; Tried to transition from state: ${from} but current state is: ${this.sm.getCurrentState()}`);
            }
       }, newTimeoutMs);
    }

    /**
     * Configure the static parameters of this tracker, should be done before instantiation
     * @param {any} configuration Configuration of tracker 
     */
    public static Configure(configuration: any) {
        try {
            ArrivalTracker.SM_UPDATE_PERIOD_MS = configuration.SM_UPDATE_PERIOD_MS;
            ArrivalTracker.SM_LOG_PERIOD_MS = configuration.SM_LOG_PERIOD_MS;
            ArrivalTracker.POSSIBLEBODY_TO_NOBODY_INTERNAL_TRANSITION_TIMEOUT_MINS = configuration.POSSIBLEBODY_TO_NOBODY_INTERNAL_TRANSITION_TIMEOUT_MINS;
        } catch (e) {
            log.error("Could not configure static variables based on configuration file: ", e);
        }
    }
}