import { ActionRuntime } from '../../common/ActionRuntime';
import { OpportunityDetector } from '../OpportunityDetector';
import { PODSignal } from './PODSignal';


export {}; // For typings generation purpose

/**
 * FiringSignal is a type of PODSignal
 * @private
 */
export abstract class FiringSignal extends PODSignal {

    // Firing-type signals sends messages to the detector
    protected detector: OpportunityDetector;

    /**
     * Constructor
     */
    public constructor(parent: ActionRuntime, name: string, detector: OpportunityDetector) {
        super(parent, name);
        this.detector = detector;
    }
}