import {ActionRuntime} from '../../common/ActionRuntime';
import {GoalProvider} from '../GoalProvider';
import {HJGoal} from '../goals/HJGoal';
import {HJData} from '../../common/Types';

export {}; // For Type definition purposes

/**
 * @private
 */
export class HJGoalProvider extends GoalProvider {

    private listening = false;

    constructor(parent: ActionRuntime) {
        super(parent, 'Hey Jibo Goal Provider');
    }

    public init() {
        this.setListening(true);
    }

    public dispose() {
        this.setListening(false);
    }

    /**
     * Set whether HJGoalProvider listens for hjEvent--effectively, enable or disable HJOrient
     * @param listen {boolean}
     */
    public setListening(listen:boolean){
        if (listen) { // requested to turn on listening
            if (this.listening) { // already listening
                this.log.warn(`setListening(${listen}) called when listening is already ${this.listening}`);
            } else {
                this.log.info(`enabling listening for HJ event`);
                this.parent.jibo.lps.identity.events.hjEvent.on(this.processHJBind);
                this.listening = true;
            }
        } else { // requested to turn off listening
            if (this.listening){
                this.log.info(`disabling listening for HJ event`);
                this.parent.jibo.lps.identity.events.hjEvent.removeListener(this.processHJBind);
                this.listening = false;
            } else {
                this.log.warn(`setListening(${listen}) called when listening is already ${this.listening}`);
            }
        }
    }

    private processHJBind = (data: HJData) => this.processHJ(data);

    /**
     * Processes an LPS audio data frame
     * @param {HJData} data
     */
    private processHJ(hjData: HJData) {
        this.provideGoal(new HJGoal(this.parent, hjData));

        // Here we record the hj data in memory for usage
        this.parent.memory.setHJData(hjData);
    }
}
