import {Action} from '../Action';
import {Point3, ActionResult} from '../../common/Types';
import {ActionRuntime} from '../../common/ActionRuntime';
import {expression} from 'jibo-expression-client';
import AcquireHandle = expression.AcquireHandle;
import AttentionHandle = expression.AttentionHandle;

/**
 * @private
 */
export class BasicLookat extends Action {

    // A handle to the possibly active lookat
    private _handle: AcquireHandle;
    private _mode: AttentionHandle;

    /**
     * Constructs an action object
     * @param {ActionRuntime} parent - Behavior runtime parent
     * @param {Point3} location - Look at location
     */
    constructor(parent: ActionRuntime, private location: Point3) {
        super(parent, 'Basic Lookat');
    }

    /**
     * Should be overridden by actions that want to respond to canceling
     */
    protected async cancelInternal(): Promise<any> {
        if (this._handle) {
            await this._handle.cancel();
            this._handle = null;
        }
        if (this._mode) {
            await this._mode.release();
            this._mode = null;
        }
    }

    /**
     * This method should be overridden by subclasses and provide
     * actual action run logic
     * @return {Promise<ActionResult>}
     */
    protected async runInternal(): Promise<ActionResult> {
        const expression = this.parent.jibo.expression;

        let result: ActionResult;
        try {
            this._mode = await expression.pushAttentionMode(expression.AttentionMode.COMMAND);
            const pos = this.location;
            this._handle = await expression.acquireTarget({
                position: {
                    x: pos.x,
                    y: pos.y,
                    z: Math.max(0.7, pos.z)
                }
            });
            await this._handle.promise;
            if(this._mode) {
                await this._mode.release();
                this._mode = null;
            }
            result = ActionResult.SUCCEEDED;
        } catch(e) {
            this.log.error(`'${this.name}: error: '`, e);
            result = ActionResult.FAILED;
        }

        this._handle = null;
        this.parent.events.oriented.emit();
        return result;
    }
}

export {}; // Needed for type definitions
