import {Action} from '../Action';
import {ActionRuntime} from '../../common/ActionRuntime';
import {ActionResult, SnuggleType, GoalFinishedStatus, AnimationGoalData} from '../../common/Types';
import {AnimationGoal} from "../../goal/goals/AnimationGoal";

const OpenHatchData = {
    category: 'system-states',
    includeMeta: ['hatch-opened']
};
const CloseHatchData = {
    category: 'system-states',
    includeMeta: ['hatch-closed']
};
const PluggedData = {
    category: 'system-states',
    includeMeta: ['plugged']
};
const UnpluggedData = {
    category: 'system-states',
    includeMeta: ['unplugged']
};
const AxisFaultData = {
    category: 'system-states',
    includeMeta: ['back-drive']
};
/**
 * Mapping of Snuggle Type to Animation Data
 */
const SnuggleAnimData = new Map<SnuggleType, AnimationGoalData>();
SnuggleAnimData.set(SnuggleType.HATCH_OPEN, OpenHatchData);
SnuggleAnimData.set(SnuggleType.HATCH_CLOSE, CloseHatchData);
SnuggleAnimData.set(SnuggleType.PLUG, PluggedData);
SnuggleAnimData.set(SnuggleType.UNPLUG, UnpluggedData);
SnuggleAnimData.set(SnuggleType.AXIS_FAULT, AxisFaultData);

/**
 * @private
 */
export class Snuggle extends Action {

    constructor(parent: ActionRuntime, private type: SnuggleType) {
        super(parent, `Snuggle`);
    }

    protected async runInternal(): Promise<ActionResult> {
        return await new Promise<ActionResult>(resolve => {
            this.log.info("playing snuggle", this.type);

            const animGoal = new AnimationGoal(this.parent, SnuggleAnimData.get(this.type));
            animGoal.events.finished.on((result: GoalFinishedStatus)=> {
                if (result === GoalFinishedStatus.SUCCEEDED) {
                    resolve(ActionResult.SUCCEEDED);
                } else {
                    resolve(ActionResult.FAILED);
                }
            });

            this.parent.goals.addGoal(animGoal);
        });
    }
}

export {}; // Needed for type definitions
