// External
import { SpeakerRecord } from "jibo-common-types";
// Only importing type definition
import JiboImport = require('../../../../../jibo'); // NOTE: only for type declaration, not runtime dependency
import SurpriseRequestData = JiboImport.jetstream.types.SurpriseRequestData;
// Internal
import { SkillNames } from '../../../common/Utils';
import { log as parentLog } from '../../log';
import { FiringSignal } from '../FiringSignal';


const log = parentLog.createChild('SignalSurprise'); 

export {}; // For Type definition purposes

 /**
  * SignalSurprise 
  * (Type): Firing   
  * (Handles): SkillChange
  * (Fire Condition): If the surprise skill decides not to launch a surprise category.
  * This is determined by observing a skill switch from @be/surprise directly to @be/idle (and not to @be/surprises-date or @be/surprises-ota).
  * @private
  */
export class SignalSurprise extends FiringSignal {

    public init(): void {
        this.parent.events.skillChange.on(this.handleSkillChangeBind);
    }

    public dispose(): void {
        this.parent.events.skillChange.removeListener(this.handleSkillChangeBind);
    }

    // Internal bind function 
    public handleSkillChangeBind = (data) => this.handleSkillChange(data);

    /**
     * Called when skills change
     */
    private handleSkillChange(skillChange: [string, string]): void {
        const [oldSkill, newSkill] = skillChange;
        // Check that a skill switch from @be/surprise directly to @be/idle occurred
        if (oldSkill === SkillNames.SURPRISES && newSkill === SkillNames.IDLE) {
            // This means that the surprise skill decided not to launch a surprise category.
            // Therefore send a surprise-type proactive trigger.
            log.debug("Skipped surprise event.  Sending surprise-type proactive trigger");
            const speaker: SpeakerRecord = this.parent.jibo.lps.identity.getActiveSpeaker();
            const surpriseRequest: SurpriseRequestData = {
                triggerSource: this.parent.jibo.jetstream.types.ProactiveTriggerSource.SURPRISE,
                triggerData: {
                    looperID: speaker ? speaker.idInfo.id : null,
                }
            };
            // Send to POD detector for evaluation
            this.detector.evaluate(surpriseRequest);
        }
    }
}