import {asr} from '@jibo/interfaces';
import {ActionRuntime} from '../../common/ActionRuntime';
import {GoalProvider} from '../GoalProvider';
import {SkillNames} from '../../common/Utils';
import {SSWGoal} from '../goals/SSWGoal';
import JiboImport = require('../../../../jibo'); // NOTE: only for type declaration, not runtime dependency


export {}; // For Type definition purposes

//Private class to provide a toLog() method for skill launch data
class HJNoMatch {
    public intent = 'hjNomatch';
    constructor(public text) {
    }

    public toLog() {
        return {
            intent: this.intent,
            text: '<user input removed>'
        };
    }
}

/**
 * @private
 */
export class HJNoMatchGoalProvider extends GoalProvider {

    private handleHJNoMatchBind = this.handleHJNoMatch.bind(this);

    constructor(parent: ActionRuntime) {
        super(parent, 'HJNoMatch goal provider');
    }

    init() {
        this.parent.jibo.globalEvents.shared.noGlobalMatch.on(this.handleHJNoMatchBind);
    }

    dispose() {
        this.parent.jibo.globalEvents.shared.noGlobalMatch.off(this.handleHJNoMatchBind);
    }

    handleHJNoMatch(data: JiboImport.jetstream.types.SuccessTurnResult) {
        // Only generate HJNoMatch goals when in Idle (and we know the ASR wasn't garbage)
        if (this.parent.currentSkillName === SkillNames.IDLE &&
            data.result.asr.annotation !== asr.ASRAnnotation.GARBAGE) {
            this.provideGoal(new SSWGoal(this.parent, {
                skillName: SkillNames.IDLE,
                skillOptions: new HJNoMatch(data.result.text),
                criteria: {
                    currentSkill: SkillNames.IDLE
                }
            }, `HJNoMatch`));
        }
    }
}
