import { EventContainer } from 'jibo-typed-events';
import { ActionRuntime } from '../../common/ActionRuntime';


export {}; // For typings generation purpose

/**
 * PODSignal types are:
 * (1) Inhibiting Signal
 * (2) Firing Signal
 * @private
 */
export abstract class PODSignal extends EventContainer {

    // Reference to parent
    protected parent: ActionRuntime;
    // Name of the POD signal
    protected name: string;

    /**
     * Constructor
     */
    public constructor(parent: ActionRuntime, name: string) {
        super();
        this.parent = parent;
        this.name = name;
    }

    /**
     * Called when initializing
     */
    public abstract init(): void;

    /**
     * Called when destroying
     */
    public abstract dispose(): void;
}