import {Event, EventContainer} from 'jibo-typed-events';
import {GoalPriority} from './GoalPriority';
import {GoalProvider} from './GoalProvider';
import {State} from '../common/State';
import {GoalFinishedStatus, GoalProgressStatus, GoalOptions, GoalPriorityType} from '../common/Types';
import {ActionRuntime} from '../common/ActionRuntime';


/**
 * @class GoalEvents
 * @memberof jibo.action.goal
 * @property {Event} selected - Goal has been selected
 * @property {Event} culled - Goal has been culled
 * @property {Event} achieved - Goal has been achieved
 * @property {Event} failed - Goal has failed
 * @property {Event} removed - Goal has been removed from list
 */
export class GoalEvents extends EventContainer {

    progressChange = new Event<GoalProgressStatus>('Goal progress change');
    finished = new Event<GoalFinishedStatus>('Goal finished');

    constructor() {
        super();
    }
}

const DEFAULT_GOAL_OPTIONS: GoalOptions = {
    priority: GoalPriority.Default,
    priorityType: GoalPriorityType.REGULAR,
    maxAttempts: 1
};

/**
 * The core representation for a goal in the action system. This class
 * is subclassed for various specific types of goals.
 * @class Goal
 * @memberof jibo.action.goal
 */
export class Goal {

    /**
     * Various goal events
     * @name jibo.action.goal.Goal#events
     * @type jibo.action.goal.GoalEvents
     */
    public events = new GoalEvents();

    /**
     * @internal
     * @private
     */
    public provider: GoalProvider;
    public attempts = 0;
    public created: Date;

    /**
     * @private
     */
    options: GoalOptions;

    /**
     * @private
     */
    protected parent: ActionRuntime;

    /**
     * @private
     */
    private _finishedStatus = GoalFinishedStatus.NOT_FINISHED;

    /**
     * @private
     */
    private _progressStatus = GoalProgressStatus.INITIAL;

    /**
     * @private
     */
    constructor(parent: ActionRuntime, public name: string, options: GoalOptions = DEFAULT_GOAL_OPTIONS) {
        this.parent = parent;
        this.options = Object.assign({}, DEFAULT_GOAL_OPTIONS, options);
        this.created = parent.dateProvider.getDate();
    }

    /**
     * Returns the current goal progress
     * @returns {GoalProgressStatus}
     * @memberOf Goal
     */
    getProgressStatus(): GoalProgressStatus {
        return this._progressStatus;
    }

    /**
     * Updates the progress status. This will emit events if the status changes
     * @param {GoalProgressStatus} status
     * @memberOf Goal
     */
    setProgressStatus(status: GoalProgressStatus): void {
        if (status !== this._progressStatus) {
            this._progressStatus = status;
            this.events.progressChange.emit(status);
        }
    }

    /**
     * Returns the current finish status
     * @returns {GoalFinishedStatus}
     * @memberOf Goal
     */
    getFinishedStatus(): GoalFinishedStatus {
        return this._finishedStatus;
    }

    /**
     * Updates the finished status. This will emit events if the status changes
     * @param {GoalFinishedStatus} status
     * @memberOf Goal
     */
    setFinishedStatus(status: GoalFinishedStatus): void {
        const finishedStatusChanged = (status !== this._finishedStatus);
        this._finishedStatus = status;

        if (status !== GoalFinishedStatus.NOT_FINISHED) {
            this.setProgressStatus(GoalProgressStatus.FINISHED);
        }

        if (finishedStatusChanged) {
            this.events.finished.emit(status);
        }
    }

    /**
     * Whether this goal is eligible given the state
     * @param {State} state
     * @return {boolean}
     * @private
     */
    isEligible(state: State): boolean {
        if (this.options.criteria) {
            const criteria = this.options.criteria;
            // Start time eligible
            if (criteria.startTime && state.time < criteria.startTime) {
                return false;
            }
            // End time eligible
            if (criteria.endTime && state.time > criteria.endTime) {
                return false;
            }
            // Current skill eligible
            if (criteria.currentSkill && state.skillName !== criteria.currentSkill) {
                return false;
            }
            // Person present eligible
            if (criteria.personPresent) {
                if (state.users.map(u => u.id).indexOf(criteria.personPresent) === -1) {
                    return false;
                }
            }
        }
        return true;
    }

    /**
     * Whether this goal can be removed from a goal set since
     * its context will never be achieved
     * @param {State} state
     * @private
     */
    canBeCulled(state: State): boolean {
        if (this.options.criteria) {
            const criteria = this.options.criteria;
            return (criteria.endTime && state.time > criteria.endTime);
        }
        return false;
    }
}
