
import {Action} from '../Action';
import {ActionRuntime} from '../../common/ActionRuntime';
import {StateMachine, TraceElement} from 'jibo-state-machine';
import {ActionResult, Point3} from '../../common/Types';
import {TypedEventWaiter, EventResult} from '../../common/EventWaiter';
import * as classes from './LookatClasses';
import {AttentionMode} from 'jibo-common-types';
import {TimeUtils} from 'jibo-cai-utils';

export {}; // Needed for type definitions

/**
 * @private
 */
export class HJOrient extends Action {

    resultWaiters: [string, EventResult<any>][];
    haveReceivedResult = false;

    sm = new StateMachine();

    doesVisibleFaceExist = new classes.ChooseOrientationPointState(this.sm, this.parent, classes.AngleCalculatorType.XY);
    attendToHJLocation = new classes.AttendToState(this.sm, this.parent, 'Attend to HJ location');
    orientToInitialPerson = new classes.AttendToState(this.sm, this.parent, 'Orient to initial face');

    haveReceivedResultState = new classes.HaveReceivedResultState(this);

    waitForFace = new classes.WaitForSignals(this);
    orientToFace = new classes.AttendToState(this.sm, this.parent, 'Orient to found face');
    waitForResult = new classes.WaitForResults(this);
    done = new classes.DoneState(this.sm);


    constructor(parent: ActionRuntime, public location: Point3) {
        super(parent, 'HJOrient');

        // Here we connect the state machine
        this.sm.setInitial(this.doesVisibleFaceExist);
        this.doesVisibleFaceExist.installTransitions(this.orientToInitialPerson, this.attendToHJLocation);
        this.orientToInitialPerson.addDoneTransition(this.done);
        this.attendToHJLocation.addDoneTransition(this.haveReceivedResultState);

        // If we have not found a face
        this.haveReceivedResultState.installTransitions(this.done, this.waitForFace);
        this.waitForFace.installTransitions(this.done, this.orientToFace);
        this.orientToFace.addDoneTransition(this.waitForResult);
        this.waitForResult.addDoneTransition(this.done);
    }

    /**
     * This method should be overridden by subclasses and provide
     * actual action run logic
     * @return {Promise<ActionResult>}
     */
    protected async runInternal(): Promise<ActionResult> {
        const pmHandler = await this.parent.jibo.expression.pushAttentionMode(AttentionMode.COMMAND);

        let altHJloc = undefined;
        const now = this.parent.dateProvider.getDate().getTime();
        const hjDataMem = this.parent.memory.getHJData();
        if (hjDataMem && hjDataMem.data.alternate &&
                TimeUtils.msToSeconds(now - hjDataMem.time.getTime()) < 60) {
            altHJloc = hjDataMem.data.alternate.position;
        }

        let refPos = {hjloc: this.location};
        if (altHJloc) {
            refPos['altHJloc'] = altHJloc;
        }
        this.doesVisibleFaceExist.setReferencePositions(refPos);


        // Add all event waiters whose promises should result in Outcome.Result
        this.resultWaiters = [
            ['HJ Listen Complete', new TypedEventWaiter<any>(null, this.parent.jibo.jetstream.events.globalTurnResult).start()],
            ['HJ Listen Complete', new TypedEventWaiter<any>(null, this.parent.jibo.jetstream.events.hjOnly).start()]
        ];

        // Keep track of whether results have arrived
        this.haveReceivedResult = false;
        Promise.race(this.resultWaiters.map(e => {
            return e[1].promise.then(() => e);
        })).then((result) => {
            this.haveReceivedResult = true;
            this.log.info(`HJOrient: event waiter '${result[0]}'`);
        });

        try {
            await this.sm.start();
            return ActionResult.SUCCEEDED;
        } catch (e) {
            this.log.error('HJOrient state machine error: ', e);
            return ActionResult.FAILED;
        } finally {
            this.log.debug(`${this.name} SM trace: `, this.sm.traceToString());
            // dump time to face here
            const trace = this.sm.getTrace();
            this.log.info(`HJOrient time to face: `, this.computeTimeToFace(trace));
            this.log.info(`HJOrient had initial face?: `, this.hadInitialFace(trace));
            await pmHandler.release();
            this.resultWaiters.forEach(e => e[1].stop());
        }
    }

    protected async cancelInternal(): Promise<any> {
        this.log.warn(`'${this.name}' cancelled!`);
        this.sm.stop();
    }


    /**
     * Parse the state machine trace to determine the elapsed time between start and finding a face
     * @param {TraceElement[]} trace
     * @returns {number} milliseconds (will be Infinity if no face found)
     */
    computeTimeToFace(trace: TraceElement[]): number {
        if (trace.length < 2) {
            return Number.POSITIVE_INFINITY;
        }
        for (let i=1; i < trace.length; i++) {
            // if transition is doesVisibleFaceExist - yes - OrientToInitialPerson
            // or WaitForSignals - found face - OrientToFoundFace
            if (trace[i].transition.getDestinationState() === this.orientToInitialPerson ||
                    trace[i].transition.getDestinationState() === this.orientToFace) {
                return trace[i].timestamp - trace[0].timestamp;
            }
        }
        return Number.POSITIVE_INFINITY;
    }

    /**
     * Parse the state machine trace to determine if we got an initial face
     * @param {TraceElement[]} trace
     * @returns {boolean}
     */
    hadInitialFace(trace: TraceElement[]): boolean {
        for (let i=0; i < trace.length; i++) {
            // if transition is doesVisibleFaceExist - yes - OrientToInitialPerson
            if (trace[i].transition.getDestinationState() === this.orientToInitialPerson) {
                return true;
            }
        }
        return false;

    }

}
