import {Goal} from '../Goal';
import {ActionRuntime} from '../../common/ActionRuntime';
import {BeSSWGoalData, GoalPriorityType} from '../../common/Types';
import {GoalPriority} from '../GoalPriority';


export {}; // For Type definition purposes

/**
 * This goal gets created by Be when it wants to switch skills and is allowing Action
 * System to complete its current action
 * @internal
 */
export class BeSSWGoal extends Goal {

    constructor(parent: ActionRuntime, public data: BeSSWGoalData, name=`Be Skill Switch Goal: '${data.skillName}'`) {
        super(parent, name, {
            priority: GoalPriority.BeSkillSwitch,
            criteria: data.criteria,
            priorityType: GoalPriorityType.SINGLETON_KEEP_LAST
        });

        // Here we update the priority of the skill based on its request
        if (data.beSkillPreferences) {
            if (data.beSkillPreferences.cancelOrientOnStart) {
                // Make skill priority higher than a Hey Jibo goal
                this.options.priority = GoalPriority.HeyJibo + 1;
            }
        }
    }
}
