// External
import { TimeUtils } from 'jibo-cai-utils';
// Internal
import { ActionRuntime } from '../../../common/ActionRuntime';
import { log as parentLog } from '../../log';
import { InhibitingSignal } from '../InhibitingSignal';


export {}; // For Type definition purposes

/**
 * @private
 */
export enum HJState {
    IN_PROGRESS = "IN_PROGRESS",
    NOT_IN_PROGRESS = "NOT_IN_PROGRESS",
}

const log = parentLog.createChild('SignalHJStatus');

/**
 * SignalHJStatus
 * (Type): Inhibiting
 * (Pass Condition): When in state NOT_INPROGRESS
 * (Description): Ensures we are not interrupting the time between a HJheard and a successful skill switch.
 *                When a HJ is heard, state is in INPROGRESS.
 *                When a skill switch is heard, state changes to NOT_INPROGRESS.
 *                State also changes to NOT_INPROGRESS after a timeout set by HJ_EXPIRE_TIMEOUT (Default: 27 seconds).
 * @private
 */
export class SignalHJStatus extends InhibitingSignal {

    // Set to 27 seconds since in Jetstream global_sosTimeout_sec is 7 seconds and global_maxSpeechTimeout_sec is 20 seconds.
    public static HJ_EXPIRE_TIMEOUT_MS = TimeUtils.secondsToMs(27);
    // Maintains the current state info
    private currState: HJState = HJState.NOT_IN_PROGRESS;
    // Reference to the timeout handler that is created to expire an HJ later in time.
    private timeoutHandle  = null;

    /**
     * Constructor
     */
    public constructor(parent: ActionRuntime, name: string) {
        super(parent, name);
        // Super important: tells Be's Timerspy that we are allowed to persist across skill boundaries
        (<any>this.handleHJExpiredTimeoutBind).isGlobalTimer = true;
    }

    public init(): void {
        this.parent.jibo.jetstream.events.hjHeard.on(this.handleHJHeardBind);
        this.parent.events.skillChange.on(this.handleSkillChangeBind);
    }

    public dispose(): void {
        this.parent.jibo.jetstream.events.hjHeard.removeListener(this.handleHJHeardBind);
        this.parent.events.skillChange.removeListener(this.handleSkillChangeBind);
    }

    /**
     * Get the current HJ State
     */
    public getState(): HJState {
        return this.currState;
    }

    /**
     * Evaluates whether a HJheard is still in progress of a possible skill switch or not
     * Pass: NOT_INPROGRESS
     * Fail: Anything else
     */
    public evaluate(): boolean {
        if (this.currState === HJState.NOT_IN_PROGRESS) {
            log.debug("Passed: HJStatus is " + this.currState);
            return true;
        } else {
            log.info("Failed: HJStatus is " + this.currState);
            return false;
        }
    }

    /**
     * Resets status to defaults
     */
    protected reset(): void {
        this.currState = HJState.NOT_IN_PROGRESS;
        this.timeoutHandle = null;
    }

    // Internal Bind Function
    private handleHJHeardBind = () => this.handleHJHeard();

    /**
     * Called whenever HJ is heard. Updates state to INPROGRESS and sets the timer.
     */
    private handleHJHeard(): void {
        this.currState = HJState.IN_PROGRESS;
        this.timeoutHandle = this.parent.jibo.timer.setTimeout(this.handleHJExpiredTimeoutBind, SignalHJStatus.HJ_EXPIRE_TIMEOUT_MS);
        log.debug("HJ heard.  HJStatus is in state: " + this.currState);
    }

    // Internal bind Function
    private handleHJExpiredTimeoutBind = () => this.handleHJExpiredTimeout();

    /**
     * Called when the timeout set in handleHJHeard expires.
     */
    private handleHJExpiredTimeout(): void {
        this.currState = HJState.NOT_IN_PROGRESS;
        log.debug("Timeout expired. HJStatus is in state: " + this.currState);
    }
    // Internal bind Function
    private handleSkillChangeBind = (data) => this.handleSkillChange(data);

    /**
     * Called whenever a skill switches. Updates state to NOT_IN_PROGRESS.
     */
    private handleSkillChange(skillChange: [string, string]): void {
        const [, newSkill] = skillChange;
        if (this.currState === HJState.IN_PROGRESS) {
            this.currState = HJState.NOT_IN_PROGRESS;
            log.debug("Skill Change to " + newSkill + ". HJStatus is in state: " + this.currState);

            // Clear timer
            if (this.timeoutHandle) {
                log.debug("Skill switch occured. Clearing out timeout");
                this.parent.jibo.timer.clearTimeout(this.timeoutHandle);
                this.timeoutHandle = null;
            }
        }
    }

    /**
     * Configure the static parameters of this signal, should be done before instantiation
     * @param {any} configuration Configuration of signal 
     */
    public static Configure(configuration: any) {
        try {
            SignalHJStatus.HJ_EXPIRE_TIMEOUT_MS = TimeUtils.secondsToMs(configuration.HJ_EXPIRE_TIMEOUT_SECS);
        } catch (e) {
            log.error("Could not configure static variables based on configuration file: ", e);
        }
    }
}